            { 738201047, "シドニー" },
            { 738201048, "ノクト" },
            { 738201049, "おーい 休憩してるの？ 王子" },
            { 738201050, "そんなとこ また何かお使いか？" },
            { 738201051, "ハハ そういうつもりじゃなかったけど" },
            { 738201052, "でも 忙しいんだろ？" },
            { 738201053, "うん だけど今日はちょっと別仕事 これから外に行こうかと思って" },
            { 738201054, "面白いものを見つけたって 情報もらったんだ なかなか手に入らないワックス" },
            { 738201055, "レガリアに使えそうだから 取りに行ってこようと思って" },
            { 738201056, "なら オレたちで行くわ" },
            { 738201057, "ええ？" },
            { 738201058, "レガリアに使うんだろ？" },
            { 738201059, "そのつもり じゃあ お願いしようかな 探すの手間がかかるかもしんないけど" },
            { 738201060, "手間？" },
            { 738201061, "落っこちてたのを見かけたって話だからさ" },
            { 738201062, "見つかったんだ よかった うん 意外と状態よさそう" },
            { 738201063, "これを使うとね 車体の空気抵抗が減って 燃費がよくなるんだよ" },
            { 738201064, "へえ" },
            { 738201065, "ごめん そのまま信じないで そういう噂までされてたものってこと" },
            { 738201066, "それだけ質がいいんだよ 劣化も少なくてさ さすがは王都製だなぁ ってね" },
            { 738201067, "30年前の障壁で出荷が制限されたから 幻の品になっちゃったんだって" },
            { 738201068, "へえ" },
            { 738201069, "じいじもぜんぜん王都に行かなかったし 私も数えるくらいしか見たことない" },
            { 738201070, "まあ まずは塗ってみない？ 燃費の効果もあるかもしれないよ？" },
            { 738201071, "じゃ 試してみたくなったら 言ってね" },
            { 738201072, "あれ 今日はのんびりしてるの？" },
            { 738201073, "まあな お使いか？ 何かあれば手伝うけど？" },
            { 738201074, "ほんと？ まあ いろいろあるけど でもそんなに気遣わなくていいよ？" },
            { 738201075, "いや レガリアで世話になってるし" },
            { 738201076, "ふーむ じゃあ あとでお礼するからさ 鉱石探し 頼んじゃおうかな" },
            { 738201077, "ありがとう 王子 ハンターでやっていけそうだね" },
            { 738201078, "えーと これは塗料 あっちは精製依頼出すか レスタルムに連絡しないと" },
            { 738201079, "さあ 今日は徹夜かな" },
            { 738201080, "マジか" },
            { 738201081, "何台か納車を待ってもらってるからね じゃ王子 コレがお礼 ステッカー" },
            { 738201082, "レガリアに貼れるよ 早速 試してみる？" },
            { 738201083, "王子 お使い お使い" },
            { 738201084, "おう" },
            { 738201085, "今度のはね レガリアの目―― ヘッドライトの中の部品だよ" },
            { 738201086, "へえ" },
            { 738201087, "まだピンとこないかもしれないけど これつけられたら旅が劇的に変わる" },
            { 738201088, "量産できればよかったのに それも王都の部品なんだよね" },
            { 738201089, "外にあるのもわずかだし" },
            { 738201090, "王都じゃもう作れねーしな" },
            { 738201091, "あ そういうことが言いたいんじゃなくてね" },
            { 738201092, "数が少ないのは惜しいけど とにかく とっても役に立つってこと" },
            { 738201093, "また取りに行くのが大変そうだけど これは絶対 レガリアにはつけてあげたい" },
            { 738201094, "レガリアも 君たちも守れるものだから ちょっと探索のお使い 頼まれてよ" },
            { 738201095, "わかった" },
            { 738201096, "王子 あった？ 見つかった？" },
            { 738201097, "おう 持ってきた" },
            { 738201098, "ほんと？ よかった" },
            { 738201099, "つけるのはもちろん王子の自由だけど でもそれ 一回くらいは使ってみて" },
            { 738201100, "これ 普通と何が違うんだ？" },
            { 738201101, "シガイに襲われなくなるんだよ その強力な光で シガイが逃げるから" },
            { 738201102, "へえ すげえ" },
            { 738201103, "でしょ？ これがもっと普及してから 障壁が閉じてればね" },
            { 738201104, "もう20年前か 夜 走ってた車が シガイに襲われたって事故があって" },
            { 738201105, "たまたま私 それを近くで見たんだけど" },
            { 738201106, "このライトつけてたら きっと無事だったんだろうなぁ―― ね" },
            { 738201107, "え ああ" },
            { 738201108, "じゃあ これ 使いたくなったら言って ほんとに探索 お疲れ様" },
            { 738201110, "酒場" },
            { 738201111, "ブレイクの入口" },
            { 738201112, "村" },
