            { 738201177, "インタラクト" },
            { 738201178, "じゃあ そろそろ行くよ" },
            { 738201179, "あの じいさんの言っていること 信じてるのか？" },
            { 738201180, "ああ" },
            { 738201181, "可能性があるならばやるだけ" },
            { 738201182, "タンタの力は絶大だ よく考えろ" },
            { 738201183, "力なら こっちにもある" },
            { 738201184, "……死ぬなよ" },
            { 738201185, "誰だ！" },
            { 738201186, "生き残りがいるとはな" },
            { 738201187, "おい お前" },
            { 738201188, "フレイだ　サンクチュアリシティから来た" },
