            { 738201304, "そ　てかさ" },
            { 738201305, "タンタ・サイラの城に行く道を教えろ" },
            { 738201306, "……" },
            { 738201307, "知らない？" },
            { 738201308, "あの……" },
            { 738201309, "知ってるやつは？" },
            { 738201310, "待ちなさい！ 待ちなさいったら！" },
            { 738201311, "おーい 誰か知らないかー" },
            { 738201312, "ちょっと聞いてるの？" },
            { 738201313, "だれかー 知ってるやつー" },
            { 738201314, "少し暑いが 風が吹くと心地いいものだな" },
            { 738201315, "人間は不便だな　何か食べないと死んでしまうんだろ？" },
            { 738201316, "フレイ…… たまにはちゃんと風呂に入れよ" },
            { 738201317, "ちょっと質問なのだが…… 迷ってるのではないか？" },
            { 738201318, "静かだな…… なにか陽気な歌でも歌ってみようじゃないか" },
            { 738201319, "さぁ フレイ お手並み拝見だ" },
            { 738201320, "あれは危険だ いまは戦いを回避すべきだと思う" },
            { 738201321, "その調子だ！" },
            { 738201322, "その攻撃ではダメだ！" },
            { 738201323, "しっかりしろ！" },
            { 738201324, "いまの攻撃は避けられたはずだ！" },
            { 738201326, "まずまず だな" },
            { 738201328, "あそこさ 誰かエレベーターつけてくんないかなー……" },
            { 738201329, "なんだ 怖いのか？" },
            { 738201330, "え？ いや？\n怖くない　全然　もちろん　怖いはずがない" },
            { 738201331, "……はぁ" },
            { 738201332, "それ" },
            { 738201333, "また飛ぶのか……" },
            { 738201334, "もう慣れただろ\n慣れは恐怖を克服する調味料だ" },
            { 738201335, "聞いたことないぞ？　……さてと" },
            { 738201336, "えーい！" },
            { 738201339, "……やっぱナシ　ナシよりのナシ\nジェットコースターも嫌いだったし" },
            { 738201340, "やめるのか？　それもいい\nだが 今から君を“臆病者“と呼ぶことにする" },
            { 738201341, "そっちの方が嫌いだ\n……いこう" },
            { 738201342, "は！" },
            { 738201351, "っぐ……" },
            { 738201352, "ナイスジャンプ　君の勇気に敬意を" },
            { 738201353, "ナイスキャッチ　サンキューカフ" },
            { 738201354, "？ ……ここ 前と違う気が……" },
            { 738201355, "まずは前進だ　気を抜くなよ" },
