            { 738202033, "この村…思った以上に賑やかだな" },
            { 738202034, "観光も悪くないが、さっさと用事を済ましたら？" },
            { 738202035, "用事？…用事なんかあったっけ？" },
            { 738202036, "冒険の準備…してないだろう？" },
            { 738202037, "アイテムを買い足しな" },
            { 738202038, "少し満足したな" },
            { 738202039, "満足したのなら、そろそろ買い物でもするか？" },
            { 738202040, "そろそろ、買い物しに行かないか？" },
            { 738202041, "フレイ…" },
            { 738202042, "いいよ、行こうか" },
            { 738202043, "キミが協力的で助かった" },
            { 738202044, "あいよ" },
            { 738202045, "今そんな気分じゃない" },
            { 738202046, "はっきり言って、キミは合理的ではないな" },
            { 738202047, "人間ってそんなもんだ" },
            { 738202048, "人間ではなくて心から嬉しく思っている" },
            { 738202049, "行かない" },
            { 738202050, "キミねぇ…" },
            { 738202051, "黙ってて" },
            { 738202052, "いいよ、黙ります" },
            { 738202053, "無視かい…" },
            { 738202054, "また無視か…" },
            { 738202055, "人に聞かれたらちゃんと答えると親に教わっていないの？" },
            { 738202056, "…親なんていないからね" },
            { 738202057, "…悪かった" },
            { 738202058, "…" },
            { 738202062, "買い物" },
            { 738202063, "[ Debug ] Put Shelter" },
            { 738202064, "Travel to this location?" },
            { 738202067, "この魔法を試してみようぜ！" },
            { 738202068, "分かった！" },
            { 738202069, "今はいい！" },
            { 738202070, "集中で聞こえなかったか…" },
            { 738202071, "<Unknown1>" },
            { 738202072, "こんにちは" },
            { 738202073, "あんた、噂のブレイクに入れる子でしょう？\n本物初めてみた" },
            { 738202074, "人気ものだね" },
            { 738202075, "ブレイクに入れるってそんなにすごいことなの？" },
            { 738202076, "まぁ…僕らが入ったらすぐ魔物になってしまうもん" },
            { 738202077, "そうなのか…" },
            { 738202078, "とにかく、シパール一番ジューシーなリンゴの店へようこそ" },
            { 738202079, "リンゴ１つをください" },
            { 738202080, "５Gだよ" },
            { 738202081, "やば、地球のお金しかない…" },
            { 738202082, "ごめんなさい、お金…持ち合わせていないんだ" },
            { 738202083, "それなら残念ね、稼いだらまた戻って頂戴？" },
            { 738202084, "オーデンから伝言があるんだ\n明日リンゴパイを取りに行くって" },
            { 738202085, "明日ね、了解、ありがとう" },
            { 738202086, "いや…また戻ってくるよ" },
            { 738202087, "おう、いつでもどうぞ" },
            { 738202088, "あのね、アタシのことわかっているよね" },
            { 738202089, "は、はい" },
            { 738202090, "リンゴ一個の料金を取るより、こうしようよ\nアタシブレイクでいいものを取ったら持ってくる…どうだい？" },
            { 738202091, "な…なるほど…何個がいいですか？" },
            { 738202092, "３個で" },
            { 738202093, "５個" },
            { 738202094, "５個" },
            { 738202095, "はい…えと…５個…もらってください。" },
            { 738202096, "ありがとうね\nいいもの見つけたら持ってくるから" },
            { 738202097, "強引にリンゴをもらえば？" },
            { 738202098, "強引にリンゴをもらう" },
            { 738202099, "買う" },
            { 738202100, "伝言を伝える" },
            { 738202101, "立ち去る" },
            { 738202104, "カフ" },
            { 738202105, "ねぇ、カフ" },
            { 738202106, "…カフ！（ささやく）" },
            { 738202107, "おい、カフ！（ささやく）" },
            { 738202108, "カフ！" },
            { 738202109, "カっフ！" },
            { 738202110, "ああ" },
            { 738202111, "なんだ" },
            { 738202112, "聞いてる" },
            { 738202115, "ねぇ、なんか、ないの？" },
            { 738202116, "次、どこ行けばいいと思う？" },
            { 738202117, "さっきの提案悪くなかったかも" },
            { 738202118, "では、やるか？" },
            { 738202119, "やっぱ、やめるわ" },
            { 738202120, "では、本来やるべきことに戻るか" },
            { 738202121, "やっぱ、さっきの提案ないわ" },
            { 738202122, "おい、間抜け" },
            { 738202123, "何?" },
            { 738202124, "人の戦い方に口出しはしたくないが\nこの魔法を使ったらどうだ？" },
            { 738202125, "おい、使ったことない魔法があるじゃないか？" },
            { 738202126, "ん…こいつなら、この魔法が効くと思うぞ" },
            { 738202127, "まずはあの敵を狙うべきじゃないのか？" },
            { 738202128, "この魔法を使ったらどうだ？" },
            { 738202129, "な、これはどうだ？" },
            { 738202131, "ん…間抜け、回復だ！" },
            { 738202132, "回復しなくていいのか？" },
            { 738202133, "ん…体を強化しよう" },
            { 738202134, "これを使おう" },
            { 738202135, "フレイ！" },
            { 738202136, "痛っ…" },
            { 738202137, "作戦変えたほうがいいんじゃないか？" },
            { 738202138, "じゃどうすんのよ？" },
            { 738202139, "ん…この魔法で行こう" },
            { 738202140, "ん…この薬を使おう" },
            { 738202141, "わかった" },
            { 738202142, "OK!" },
            { 738202143, "了解" },
            { 738202144, "言われなくても…" },
            { 738202145, "口出さなくていいから" },
            { 738202146, "はいはい、口出しません" },
            { 738202147, "黙ってて" },
            { 738202148, "微妙" },
            { 738202149, "それどころじゃない" },
            { 738202150, "自分で考える" },
            { 738202151, "いいんじゃないか" },
            { 738202152, "悪くない" },
            { 738202153, "これいいじゃん" },
            { 738202154, "ん…だろ？" },
            { 738202155, "…やっぱないわ" },
            { 738202157, "なんだ、そして間抜けってやめてくれないか" },
            { 738202158, "間抜けじゃない…で、何？" },
            { 738202159, "…何？" },
            { 738202160, "近くに休めそうな所がありそう\nひといきをいれたら？" },
            { 738202161, "近くに使えるものがありそうだ\n取って行かないか？" },
            { 738202162, "この近くに薬を調達できる所があるみたい\n寄って行かないか？" },
            { 738202163, "一旦シパールに戻ろう" },
            { 738202164, "行くべき所があるんだろう？\n急ごう" },
            { 738202165, "そろそろ出発するか" },
            { 738202166, "今ならどうだ？" },
            { 738202167, "あれを見ろ" },
            { 738202168, "どこ行けばいい？" },
            { 738202169, "案内して" },
            { 738202170, "そうしよう" },
            { 738202171, "あっちだ" },
            { 738202172, "案内する" },
            { 738202173, "ん…素直でよろしい" },
            { 738202174, "その言い方…" },
            { 738202175, "ねぇ、しばらく何もしゃべらないでくれる？" },
            { 738202176, "はいはい、しゃべりません" },
            { 738202177, "後でね" },
            { 738202178, "ん…いいよ" },
            { 738202179, "要らない" },
            { 738202180, "黙ってて" },
            { 738202181, "そうかいそうかい" },
            { 738202182, "お前、合理的じゃないな…" },
            { 738202183, "無視か…" },
            { 738202184, "また無視か…" },
            { 738202185, "間抜け…喋り方…わかっているよな？" },
            { 738202186, "…" },
            { 738202187, "…提案するまでもないか" },
            { 738202188, "…それどころじゃないか…" },
            { 738202189, "ん…一旦なしで" },
            { 738202190, "それ、いただいてしまっていいんじゃないか？" },
            { 738202191, "フレイ、ブレイクのことについて聞いてみよう" },
            { 738202192, "黙って" },
            { 738202193, "あんたさ、すごいことできないの\nこう…剣になってシャキンシャキンとかさ" },
            { 738202194, "剣は無理だな…サジェストするくらいならできる\nどの敵を先に倒すべきか、どの魔法を使うか…" },
            { 738202195, "サジェストね…もう超～ありがたい" },
            { 738202196, "いやだったらいやと言えばいい、聞いておいて損はないぞ" },
            { 738202197, "ストップ、後ろが崖だ" },
            { 738202198, "これは勝てない、逃げたほうがいいな" },
            { 738202199, "距離を取れ" },
            { 738202200, "後ろから敵が接近してきてる" },
            { 738202201, "いいぞ、あとすこしだけ" },
            { 738202202, "ありがとう！" },
            { 738202203, "わかった！" },
            { 738202204, "向こうに敵がいる、気をつけろ" },
            { 738202205, "左に敵がいそうだ" },
            { 738202206, "右に敵がいる" },
            { 738202207, "わかった" },
            { 738202208, "暗くなってきたな…シェルターの場所を考えたほうがよさそうだ" },
            { 738202209, "あと少しだけ目的地にだな" },
            { 738202210, "おい、間抜け" },
            { 738202211, "おい" },
            { 738202212, "あいつの弱点はあそこだ!" },
