            { 738203031, "Sends an ivy whip snaking out around you that deals damage over the surrounding area, and heals based on how much damage it does." },
            { 738203032, "Bind" },
            { 738203033, "Ties enemies up in a tangle of weeds." },
            { 738203034, "Implant" },
            { 738203035, "Fires seeds into enemies that continue to deal damage for a short period." },
            { 738203036, "Disperse" },
            { 738203037, "Causes flowers to spring up in a spot of your choosing that pick up nearby rocks and fling them at enemies." },
