            { 738203053, "Summons a magical sword that slices into the enemy." },
            { 738203072, "Charge" },
            { 738203073, "A forward rush with a magical shield that drives enemies back on impact." },
            { 738203074, "Bombardier" },
            { 738203075, "Kicks enemies backward with fiery force, triggering an explosion that damages foes over an area." },
            { 738203076, "Firetrap" },
            { 738203077, "Causes lava to bubble up beneath the enemy and simmer away for a hot minute." },
            { 738203078, "Crucible" },
            { 738203079, "Encloses the area in fiery walls, inside which attack power is increased." },
            { 738203080, "Legion" },
            { 738203081, "Summons a host of fiery soldiers to attack the enemy." },
            { 738203082, "Aegis" },
            { 738203083, "Summons the protective power of cleansing flame to erase any attack- or defense-reducing effects." },
            { 738203084, "Fusillade" },
            { 738203085, "Summons multiple fiery swords that protect you by attacking enemies while you're charging up your magic." },
            { 738203086, "Beacon" },
            { 738203087, "A light in the darkness that increases the speed at which stamina recharges, but also makes you easier to spot." },
