            { 738203397, "Creates a defensive shield while charging, which is blasted forward in pieces when released." },
            { 738203398, "Shield Shot Lv. 2" },
            { 738203399, "Creates a larger defensive shield while charging, which is blasted forward with more force when released." },
            { 738203400, "Shield Shot Lv. 3" },
            { 738203401, "Creates an even larger defensive shield while charging, which is blasted forward with even more force when released." },
            { 738203402, "Scatter Shot Lv. 1" },
            { 738203403, "Fires a steady stream of rocks while charging, then unleashes a high-impact, long-range projectile when released." },
            { 738203404, "Scatter Shot Lv. 2" },
            { 738203405, "Fires rocks harder and faster while charging, and unleashes a higher-impact long-range shot when released." },
            { 738203406, "Scatter Shot Lv. 3" },
            { 738203407, "Fires rocks even harder while charging, and unleashes an even higher-impact long-range shot when released." },
            { 738203408, "Arc Slice Lv. 1" },
            { 738203409, "A lightning-quick area slice with a huge magical sword. In midair, it won't go as far, but will deal more damage." },
            { 738203410, "Arc Slice Lv. 2" },
            { 738203411, "An improved area slice with a huge magical sword. When unleashed in midair, it sends out a stunning shockwave." },
            { 738203412, "Arc Slice Lv. 3" },
            { 738203413, "An insane area slice with a huge magical sword. When unleashed in midair, it sends out a devastating shockwave." },
            { 738203414, "Blast Slice Lv. 1" },
            { 738203415, "Throws a magical spear at an enemy that damages them and the surrounding area. Flies further and hits harder from midair." },
            { 738203416, "Blast Slice Lv. 2" },
            { 738203417, "Throws an improved magical spear that damages an enemy and the surrounding area. Flies further and hits harder from midair." },
            { 738203418, "Blast Slice Lv. 3" },
            { 738203419, "Throws a deadly magical spear that damages an enemy and the surrounding area. Flies further and hits harder from midair." },
            { 738203420, "Rage Slice Lv. 1" },
            { 738203421, "Unleashes a flurry of magical punches while charging, then sends enemies flying with explosive force when released." },
            { 738203422, "Rage Slice Lv. 2" },
            { 738203423, "Unleashes more powerful punches while charging, and explodes with more force when released." },
            { 738203424, "Rage Slice Lv. 3" },
            { 738203425, "Unleashes even more powerful punches while charging, and explodes with even more force when released." },
            { 738203426, "Chain Bolt Lv. 1" },
            { 738203427, "Fires an arrow upon charging, and another upon release. If both strike in the same place, bonus damage is dealt." },
            { 738203428, "Chain Bolt Lv. 2" },
            { 738203429, "Arrow damage and bonus damage are increased. Additionally, if both strike in the same place, the enemy can be paralyzed." },
            { 738203430, "Chain Bolt Lv. 3" },
            { 738203431, "Arrow damage and bonus damage are further increased. Additionally, if both strike in the same place, the enemy can be paralyzed." },
            { 738203432, "Fan Bolt Lv. 1" },
            { 738203433, "Fires a spray of magically linked arrows out in front of you, dealing damage over the entire area they cover." },
            { 738203434, "Fan Bolt Lv. 2" },
            { 738203435, "Fires a spray of magically linked arrows out in front of you that deal more damage over the area they cover." },
            { 738203436, "Fan Bolt Lv. 3" },
            { 738203437, "Fires a spray of magically linked arrows out in front of you that deal even more damage over the area they cover." },
            { 738203438, "Cluster Bolt Lv. 1" },
            { 738203439, "Fires an arrow which breaks up in midair, raining down bolts that deal damage over a wide area." },
            { 738203440, "Cluster Bolt Lv. 2" },
            { 738203441, "Fires an arrow which breaks up in midair, raining down bolts that deal more damage over a wider area." },
            { 738203442, "Cluster Bolt Lv. 3" },
            { 738203443, "Fires an arrow which breaks up in midair, raining down bolts that deal even more damage over an even wider area." },
            { 738203444, "Pulse Dart Lv. 1" },
            { 738203445, "Sends beams of light at any darts embedded in enemies that shoot right through them, dealing damage as they go." },
            { 738203446, "Pulse Dart Lv. 2" },
            { 738203447, "Sends beams of light at any darts embedded in enemies that shoot right through them, dealing more damage." },
            { 738203448, "Pulse Dart Lv. 3" },
            { 738203449, "Sends beams of light at any darts embedded in enemies that shoot right through them, dealing even more damage." },
            { 738203450, "Storm Dart Lv. 1" },
            { 738203451, "Emits electrical energy over the immediate area while charging, then unleashes a shockwave when released that will also strike any darts embedded in e..." },
            { 738203452, "Storm Dart Lv. 2" },
            { 738203453, "Emits electrical energy while charging, then unleashes a more powerful shockwave over a wider area when released that will also strike any darts embed..." },
            { 738203454, "Storm Dart Lv. 3" },
            { 738203455, "Emits electrical energy while charging, then unleashes an even more deadly shockwave over an even wider area when released that will also strike any d..." },
            { 738203456, "Seeker Dart Lv. 1" },
            { 738203457, "Emits lightning that seeks out any darts embedded in enemies, dealing damage as it goes." },
            { 738203458, "Seeker Dart Lv. 2" },
            { 738203459, "Increases the power of electrical attacks." },
            { 738203460, "Seeker Dart Lv. 3" },
            { 738203461, "Further increases the power of electrical attacks." },
            { 738203480, "[ Debug ] Craft Menu" },
            { 738203485, "フレイ" },
            { 738203486, "カフ" },
            { 738203487, "オーデン" },
            { 738203488, "ブレイクボブ" },
            { 738203489, "ジョヘッディ" },
            { 738203490, "衛兵" },
            { 738203491, "<iconChapterSumVfxAlt>あの少女を気にかけていた気持ちはわかるが――" },
            { 738203492, "オリヴィア" },
            { 738203493, "<iconChapterSumVfxAlt>悪気はないんだ すまない" },
            { 738203494, "彼女とは一度しか会わなかった" },
            { 738203495, "芯の強い子だった" },
            { 738203496, "<iconChapterSumVfxAlt>彼女の死に責任を感じてるのか？" },
            { 738203497, "子どもには手を出すべきじゃない" },
            { 738203498, "手を出したやつには やり返すよ　全力でね" },
            { 738203499, "<iconChapterSumVfxAlt>もしお前がサイラを殺したいというなら 俺もその意思を尊重しよう" },
            { 738203500, "お前の許可は必要ないけど お前の力は必要だね" },
            { 738203501, "<iconChapterSumVfxAlt>おぉ！　ようやく俺の価値に気付いたか" },
            { 738203502, "はぁ よくそんな自信を持っていえるね" },
            { 738203503, "<iconChapterSumVfxAlt>当たり前だ　ヴァンブレイスと呼ばれる前の姿を見せたいくらいさ" },
            { 738203504, "『カフ』ね　なに 今度は自分がどれだけ美男子だったか語るの？" },
            { 738203505, "<iconChapterSumVfxAlt>お洒落ではあったな" },
            { 738203506, "本当高慢だね お前は――" },
            { 738203507, "誰が高慢なの？" },
            { 738203508, "えと……あたしが高慢なの　そう あたし" },
            { 738203509, "そうでないとおかしいでしょ" },
            { 738203510, "タンタたちはやばい力があるらしいし そのひとりを殺すっていったのよ？" },
            { 738203511, "頭がおかしいのはどっちって話よね？" },
            { 738203512, "<iconChapterSumVfxAlt>下手な演技だな" },
            { 738203513, "そうね サイラを倒すのはとても難しいと思うわ" },
            { 738203514, "でも構わない　あいつには報いを受けさせないといけないんだ" },
            { 738203515, "彼女たちが狂う前を知ってほしかった　かつてのサイラは無実な人を傷つけたりしなかったわ" },
            { 738203516, "でも現にあのクソ女は人を殺したし あたしはそいつしか知らない" },
            { 738203517, "気持ちはわかるわ　私も街の人たちが心配だし 協力させて" },
            { 738203518, "でも戦うつもりなら その相手を知らないと" },
            { 738203519, "まずは上層街にある図書館に行ってみて　そこにサイラについての本があるはず" },
            { 738203520, "彼女を倒すには 彼女を知る必要があるわ" },
            { 738203521, "わかった ありがとう" },
            { 738203522, "待って　約束のこと忘れてないよね？" },
            { 738203523, "これのことかしら？" },
            { 738203524, "シパールに留まることを考えてくれたと思ったけど" },
            { 738203525, "そうでもないね" },
            { 738203526, "これが約束した資料よ" },
            { 738203527, "いい取引ができて良かったよ オーデン" },
            { 738203528, "私も　あなたはブレイクの本だけでなく 私の父も連れ帰ってきてくれた　この恩は一生忘れないわ" },
            { 738203529, "別にいいよ" },
            { 738203530, "父ならこの資料を解読できるわ　今は部屋にいるはずだから　ついてきて" },
            { 738203531, "そんな！　ここにいてって伝えたのに" },
            { 738203532, "ベッドの下にいないなら また犬みたいにどこかに走ってったのかもしれないね" },
            { 738203533, "父を犬と呼ばないで" },
            { 738203534, "ごめん　そういう表現があるの　失言だった" },
            { 738203535, "父を探すのを手伝ってくれない？" },
            { 738203536, "『仰せの通りに バターカップ姫』" },
            { 738203537, "これは映画の台詞で――" },
            { 738203538, "そっか　その 『映画』というのは――" },
            { 738203539, "もう！　言葉遊びをしてる場合じゃないの！　早く父を探さないと！" },
            { 738203540, "思い立ったが吉日ってね" },
            { 738203541, "見つかるよ 絶対" },
            { 738203542, "ありがとう" },
            { 738203543, "さっさと図書館に向かうぞ" },
            { 738203544, "は？" },
            { 738203545, "んー…そうだね" },
            { 738203546, "さっさと図書館に向かうぞ" },
            { 738203547, "オーデンの話聞いてた？　まずはボブを探さないとでしょ" },
            { 738203548, "あのボケ爺さん なら大丈夫だ" },
            { 738203549, "それよりもサイラを倒すための準備を急いだほうがいい" },
            { 738203550, "わかってるけど 元の世界に帰るためには ボブに次元の扉の資料を解読してもらわないと" },
            { 738203551, "それは何度も聞いた　だが俺が牢獄でした質問にはまだ答えてないぞ" },
            { 738203552, "お前はなぜそこまでしてニューヨークに帰りたいんだ？　あそこではただ惨めだったんだろ？" },
            { 738203553, "でも この世界よりはマシ" },
            { 738203554, "どちらの地獄を選ぶかはあたしの自由" },
            { 738203555, "それに 大切な猫を人にあげちゃったの" },
            { 738203556, "あたしの大切なホーマー　それは今も後悔してる　だから戻らないと" },
            { 738203557, "なんで捨てたんだ？" },
            { 738203558, "あたしの……状況が悪かったの" },
            { 738203559, "今は状況が良くなったのか？" },
            { 738203560, "もうやめて　今はただ彼女の元に帰りたいの" },
            { 738203561, "つまり お前は田舎娘オーデンとの友情より 悪臭漂う飼い猫といることを望むのか？" },
            { 738203562, "ちょっと！　ホーマーの悪口はやめて　それに臭くない" },
            { 738203563, "いつも自分の身体を舐めて綺麗にしてるし……大切な家族なの" },
            { 738203564, "怒らせたならすまない　俺がいいたかったのは……" },
            { 738203565, "カフ 今はいいから黙ってて　お前はあたしについてくればいいの" },
            { 738203566, "この辺りでボブが行きそうな場所を探してみて 早く見つけてあげないと" },
            { 738203567, "驚いた　ボブは天才だったのね" },
            { 738203568, "<iconChapterSumVfxAlt>それがあんな姿となってしまったのは本当に残念だ" },
            { 738203569, "<iconChapterSumVfxAlt>とんだ悲劇だな　タンタたちは取り返しのつかないことをした" },
            { 738203570, "因果応報ってね　いずれ彼女たちも償うときが来る" },
            { 738203571, "<iconChapterSumVfxAlt>そうだな　だがそれは俺たちの問題ではない だろ？" },
            { 738203572, "そのとおりよ　カフ" },
            { 738203573, "さぁ 今度は農園 に行ってボブを探そう" },
            { 738203574, "再会を邪魔して悪いんだけど――" },
            { 738203575, "君は誰だ？" },
            { 738203576, "思っていたよりも病状が深刻らしいな" },
            { 738203577, "フレイよ　えと あんたをあのメイステル塔から救った――" },
            { 738203578, "すまない　頭がフラフラクラクラして ――" },
            { 738203579, "――いやクラクラフラフラして" },
            { 738203580, "異世界から来た不思議な子か！" },
            { 738203581, "次元の扉の資料なんだけど――" },
            { 738203582, "ヴーッシュ！" },
            { 738203583, "そう！　ヴーッシュ！　それよ！" },
            { 738203584, "ニューヨークにヴーッシュしたいの……あの狂った女を倒したあとに" },
            { 738203585, "生きていたらだけど……" },
            { 738203586, "できるさ" },
            { 738203587, "倒すこと？　それともニューヨークに戻ること？" },
            { 738203588, "片方か もしくは両方か　どちらでもないか　わからないな" },
            { 738203589, "とんだ約束ね" },
            { 738203590, "そう 約束する　君がヴーッシュできるように　二言はない" },
            { 738203591, "最高だな！　ボケ老人の約束とは　傑作だ" },
            { 738203592, "よかった" },
            { 738203593, "見ろ！　あいつだ！　フレイって名前の！" },
            { 738203594, "<iconChapterSumVfxAlt>あれだな……逃げるか？" },
            { 738203595, "あたしも同じこと考えてた" },
            { 738203596, "（衛兵が道を開ける）" },
            { 738203597, "入れてくれるなんて予想外ね" },
            { 738203598, "<iconChapterSumVfxAlt>昨日のお前の活躍を見て　恐れをなしてるんだろう" },
            { 738203599, "相当な量があるようだが……2階の棚から調べてみるか" },
            { 738203600, "そうね　いってみよう" },
            { 738203601, "いや　1階から調べよう" },
            { 738203602, "タンタたちが狂った原因はなんだと思う？" },
            { 738203603, "<iconChapterSumVfxAlt>恐らく互いの思想が少しずつずれ 対立が起きたのだろう" },
            { 738203604, "<iconChapterSumVfxAlt>それぞれの力を互いに向け分断が起きた　そしてそれが混沌を招いた" },
            { 738203605, "<iconChapterSumVfxAlt>以前は平和だった関係も壊れ やがて孤立していった" },
            { 738203606, "<iconChapterSumVfxAlt>ついには城に閉じこもり そこからブレイクが広がっていった" },
            { 738203607, "ブレイクがタンタを狂わせたの？ それとも逆？" },
            { 738203608, "<iconChapterSumVfxAlt>恐らくすべて同時に起こったんだろう" },
            { 738203609, "なに!?" },
            { 738203610, "見つけたぞ こんちきしょうめ！" },
            { 738203611, "ほら" },
            { 738203612, "誰？　あとこれなに？" },
            { 738203613, "オーデンはお前が賢いといっていたが どうやら本がなにかも知らないみたいだな" },
            { 738203614, "いや これが本なのは知ってるけど――" },
            { 738203615, "それはサイラの城の設計図だ" },
            { 738203616, "あとさっきの本にはクラフトのレシピが入ってる　お前の役に立つだろう" },
            { 738203617, "あんたは誰？　魔法使いの妖精 なの？" },
            { 738203618, "ジョヘッディだ　ロビアンの代理で議員の相談役をしてる" },
            { 738203619, "そしてお前がサイラを倒すとほざいてたやつだな" },
            { 738203620, "まるであたしにはできないといってるみたいだね" },
            { 738203621, "サイラはタンタたちの中でも最も力が強かった" },
            { 738203622, "彼女は軍隊を指揮し その拳で相手をねじ伏せた" },
            { 738203623, "それに比べ……（フレイを見て）お前は貧弱だ" },
            { 738203624, "なんか不安になってきた……" },
            { 738203625, "この婆さんの戯言は聞くな" },
            { 738203626, "これはお前自身が選択することだ　それでこの世界は救われるかもしれない" },
            { 738203627, "タンタを倒すことで そのレルムのブレイクも止まるだろう" },
            { 738203628, "だが 私はその貧弱な手までは支えられない" },
            { 738203629, "やっぱり魔法使いの妖精じゃないね" },
            { 738203630, "静かすぎて逆に気味悪いね" },
            { 738203631, "<iconChapterSumVfxAlt>平和でいいじゃないか" },
            { 738203632, "<iconChapterSumVfxAlt>それともブレイクビーストが周りにいたほうが落ち着くのか？" },
            { 738203633, "いや　ただホラー映画の展開だと こういうシーンのあとにやばいことが起きるんだよね" },
            { 738203634, "ほらやっぱり……" },
            { 738203635, "<iconChapterSumVfxAlt>隠れろ！" },
            { 738203636, "なんであいつに狙われてるの？　あたしのこと探してるのよね" },
            { 738203637, "<iconChapterSumVfxAlt>そうみたいだな" },
            { 738203638, "<iconChapterSumVfxAlt>だが 今は戦いを避けたほうがいいだろう" },
            { 738203639, "そうね" },
            { 738203640, "……どっかへいったみたい" },
            { 738203641, "<iconChapterSumVfxAlt>戻ってこないうちに　さっさと先へ進むぞ" },
            { 738203642, "なんなのこれ!?" },
            { 738203643, "<iconChapterSumVfxAlt>どうやらブレイクがとても濃い場所に入ってしまったらしい" },
            { 738203644, "<iconChapterSumVfxAlt>高密度なブレイクが周囲を巻き込み すべてを破壊しようとしてるんだ" },
            { 738203645, "そう思う？　まるで台風と地震の間に発生した津波と竜巻ね" },
            { 738203646, "<iconChapterSumVfxAlt>直に収まるはずだ　それまではなんとか堪えるんだ" },
            { 738203647, "いうだけなら簡単よ" },
            { 738203648, "おい！　あそこならこいつをやり過ごせるんじゃないか？" },
            { 738203649, "そうね　いこう……！" },
            { 738203650, "自分で探すから ちょっと黙ってて！" },
            { 738203651, "いそげ！" },
            { 738203652, "なんであたしが帰りたいかわかる？　この世界が最低だからよ！" },
            { 738203653, "確かにさっきのあれが少し過酷だったのはわかるが――" },
            { 738203654, "少し!?　どう考えてもヤバすぎでしょ！" },
            { 738203655, "自分の家がなくても構わない！" },
            { 738203656, "あたしはこの地獄に留まるより ニューヨークの道端でホーマーと一緒に暮らすことを選ぶわ！" },
            { 738203657, "とりあえず休もう　朝になればきっと状況も良くなってる" },
            { 738203658, "はっ 『良くなってる』ね" },
            { 738203659, "明日あの恐ろしいクソ女と戦うことをお忘れかしら" },
            { 738203660, "<iconChapterSumVfxAlt>気分は良くなったか？" },
            { 738203661, "あんまり　悪夢を見たけど ここよりもマシだった" },
            { 738203662, "<iconChapterSumVfxAlt>美しいと思うけどな" },
            { 738203663, "ここが殺意と憎悪で満ちてるって意味ならそうね" },
            { 738203664, "<iconChapterSumVfxAlt>狂気には繊細な優美さが含まれてるってことだ" },
            { 738203665, "<iconChapterSumVfxAlt>破壊と混沌はある種それの創造物なんだよ" },
            { 738203666, "深いね　まるで連続殺人犯みたい" },
            { 738203667, "<iconChapterSumVfxAlt>なんだと？" },
            { 738203668, "『破壊と混沌はある種それの創造物なんだよ』" },
            { 738203669, "<iconChapterSumVfxAlt>俺はそんな声じゃない" },
            { 738203670, "これ以上ないぐらい似てると思うよ" },
            { 738203671, "<iconChapterSumVfxAlt>『これ以上ないぐらい似てると思うよ』" },
            { 738203672, "<iconChapterSumVfxAlt>どうだ！　声真似も負けてないな" },
            { 738203673, "アホらし" },
            { 738203674, "<iconChapterSumVfxAlt>混沌に内在する秩序については 俺のほうが造形は深いみたいだな" },
            { 738203675, "そうね ハンニバル" },
            { 738203676, "<iconChapterSumVfxAlt>誰だ？　あぁ……地球のジョークか" },
            { 738203677, "ピンポン" },
            { 738203678, "あそこね　兵士たちが厳重に守ってるけど　もらった設計図を見てみようか" },
            { 738205568, "Head for the Objective" },
            { 738205569, "Defeat All Enemies" },
            { 738205570, "Main Quest" },
            { 738205577, "ロビアンはシンタに仕える直臣で学者でもあり 魔法や歴史 医療など幅広い分野に精通していた" },
            { 738205578, "ブレイク発生後 ロビアンはアーシアの指導者となり 混乱する人々をシパールへと導いた" },
            { 738205579, "混乱が落ち着いた後 ロビアンはブレイクの研究をおこなっていたが ある時ブレイクに巻き込まれ行方不明となった" },
            { 738205580, "アーシアには４人のタンタたちがいる　彼女たちの名は サイラ プラーヴ オーラス シンタ" },
            { 738205581, "現在のタンタたちは悪の統治者として 我々アーシアの民を苦しめている" },
            { 738205582, "ブレイクを生み出しているのはタンタたちであり ブレイクによって世界は滅亡に瀕している" },
            { 738205583, "20年前 彼女たち４人のタンタは みな心優しき統治者だった" },
            { 738205680, "Cancel" },
            { 738205682, "The Enemy of My Enemy" },
            { 738205683, "A Common Goal" },
            { 738205684, "Talk to the Tavernkeeper" },
            { 738205685, "Auden's Advice" },
            { 738205686, "No Access to the Archives?" },
            { 738205687, "Bob Goes On Ahead" },
            { 738205688, "Time to Head Out" },
            { 738205693, "<iconChapterSumVfxAlt>さぁ、早く城に向かうぞ！" },
            { 738205694, "そんな気分上がらないけど" },
            { 738205695, "まるで要塞ね" },
            { 738205696, "<iconChapterSumVfxAlt>鉄壁のタンタに対してその表現は正しいな。" },
            { 738205697, "<iconChapterSumVfxAlt>何しろ彼女はひとりで軍隊を相手にして――" },
            { 738205698, "どこから入ったらいいんだろう" },
            { 738205699, "<iconChapterSumVfxAlt>敵は成す術なく殺された" },
            { 738205700, "そこは言わなくても――" },
            { 738205701, "<iconChapterSumVfxAlt>そしてその血で彼女は身を洗った！" },
            { 738205702, "やめて！　誰も言ってないでしょ！" },
            { 738205703, "<iconChapterSumVfxAlt>誇張しただけだ" },
            { 738205704, "しないで" },
            { 738205705, "<iconChapterSumVfxAlt>すまない　サイラも普通の風呂に入ってたはずさ" },
            { 738205706, "集中して　まずは門を目指そう" },
            { 738205707, "意外に静かだね" },
            { 738205708, "<iconChapterSumVfxAlt>好都合だろ　さっさとサイラに会いに行くぞ" },
            { 738205709, "誰かいる？" },
            { 738205710, "<iconChapterSumVfxAlt>確かにいたな　昔の住人が" },
            { 738205711, "かわいそうだけど　倒して先に進むよ" },
            { 738205712, "この化け物たちって……" },
            { 738205713, "<iconChapterSumVfxAlt>言っただろ　ブレイク化したプレイノストの住人だ" },
            { 738205714, "ブレイクから逃げられなかったんだね" },
            { 738205715, "やっと兵士のおでましだね" },
            { 738205716, "<iconChapterSumVfxAlt>城に近づいたからな　気を抜くなよ" },
            { 738205717, "なにこれ　入れないじゃん" },
            { 738205718, "<iconChapterSumVfxAlt>入口を塞いで侵入させない……か　確かに難攻不落だな" },
            { 738205719, "<iconChapterSumVfxAlt>さあ　裏に回ってみるか？" },
            { 738205720, "城の横に脇道があったよね　あんたも設計図見たでしょ？" },
            { 738205721, "<iconChapterSumVfxAlt>見るのは感心だが　昔の設計図だ" },
            { 738205722, "行ってみよう　他の道を探すより 確実で近道でしょ" },
            { 738205723, "<iconChapterSumVfxAlt>やれやれ" },
            { 738205724, "設計図では　この辺から入れるはずなんだけど…" },
            { 738205725, "レディッグの粛清……図書館の本にも書いてあったね" },
            { 738205726, "アーシアはこのレディッグとかいう連中に侵略されたみたい　醜い奴ら" },
            { 738205727, "<iconChapterSumVfxAlt>こっちがサイラか" },
            { 738205728, "シパールのときみたく狂って見えないね" },
            { 738205729, "<iconChapterSumVfxAlt>タペストリーなら嘘を描けるからな" },
            { 738205730, "そういうことじゃなくて" },
            { 738205731, "これがタンタたち？" },
            { 738205732, "<iconChapterSumVfxAlt>狂う前の な　それより先に進むぞ" },
            { 738205733, "なんで人を苦しめるようになったのかな？" },
            { 738205734, "権威があって強そうに見える　憧れるね" },
            { 738205735, "みんなが彼女の下で戦おうとしたのもわかる" },
            { 738205736, "<iconChapterSumVfxAlt>戦略の内だろ" },
            { 738205737, "賢そうね" },
            { 738205738, "<iconChapterSumVfxAlt>『知恵のタンタ』と言われていた" },
            { 738205739, "昔 同じような目をした先生がいたよ" },
            { 738205740, "<iconChapterSumVfxAlt>学校に行ってたのか？" },
            { 738205741, "信じないかもしれないけど こんな不良娘でも脳味噌は詰まってるの" },
            { 738205742, "<iconChapterSumVfxAlt>見かけによらないな" },
            { 738205743, "いかにもって感じ" },
            { 738205744, "<iconChapterSumVfxAlt>『審判』のタンタだ" },
            { 738205745, "だと思った　こんな女性の前に立たされることが多かったから" },
            { 738205746, "<iconChapterSumVfxAlt>法を犯したのか？" },
            { 738205747, "自慢じゃないけど　生きていくため必要だったの" },
            { 738205748, "綺麗……" },
            { 738205749, "<iconChapterSumVfxAlt>人々の憧れとして見られていたからな" },
            { 738205750, "内側から輝きが滲み出ているみたい" },
            { 738205751, "<iconChapterSumVfxAlt>『慈愛』のタンタと呼ばれていた" },
            { 738205752, "優しそうで安心する　まるで……" },
            { 738205753, "<iconChapterSumVfxAlt>それが狂気で歪んでしまったのは本当に残念だ" },
            { 738205754, "<iconChapterSumVfxAlt>昔の設計図だ　多少構造は変わっているさ" },
            { 738205755, "<iconChapterSumVfxAlt>さあ　戻って裏道でもさがすか" },
            { 738205786, "Head to the Grove" },
            { 738205787, "Head to Upper Cipal" },
            { 738205788, "Head to the Fortress" },
