            { 738206159, "Conflagration Lv. 1" },
            { 738206160, "Calls forth a fiery column that spatters enemies with magma, which remains on the ground for a short while after the attack." },
            { 738206161, "Conflagration Lv. 2" },
            { 738206162, "Hits harder and over a wider area when the buttons are held." },
            { 738206163, "Conflagration Lv. 3" },
            { 738206164, "Calls forth a fiery column that flies wildly around the battlefield when the buttons are held for even longer, dealing damage left and right." },
            { 738206165, "Cataract Lv. 1" },
            { 738206166, "Spins up a watery vortex that sucks in enemies, damaging them as it does so." },
            { 738206167, "Cataract Lv. 2" },
            { 738206168, "Spins up a watery vortex that sucks in enemies, damaging them as it does so. Holding the buttons sends pillars of water out to attack enemies." },
            { 738206169, "Cataract Lv. 3" },
            { 738206170, "Spins up a watery vortex that sucks in enemies, damaging them as it does so. Holding the buttons for even longer sends out more pillars of icy water o..." },
            { 738206171, "Tempest Lv. 1" },
            { 738206172, "Calls up lightning from the earth to electrocute enemies over a wide area." },
            { 738206173, "Tempest Lv. 2" },
            { 738206174, "Calls up lightning from the earth to electrocute enemies more viciously and over a wider area when the buttons are held." },
            { 738206175, "Tempest Lv. 3" },
            { 738206176, "Calls up lightning from the earth to electrocute enemies even more viciously and over an even wider area when the buttons are held." },
            { 738206177, "Genesis Lv. 1" },
            { 738206178, "Summons barbed branches which are fired out in front of you, skewering enemies over a wide area." },
            { 738206179, "Genesis Lv. 2" },
            { 738206180, "Hits harder and over a wider area when the buttons are held." },
            { 738206181, "Genesis Lv. 3" },
            { 738206182, "Strikes and poisons enemies over a wide area when the buttons are held for even longer." },
            { 738206183, "Leave the Archives" },
            { 738206184, "Enter Praenost" },
            { 738206185, "Black Dragon in Flight" },
            { 738206187, "Infiltrate Sila's Castle" },
            { 738206188, "Gain Entry to the Castle" },
            { 738206189, "Find a Way up to the Roof" },
            { 738206191, "しかしあのサイラ相手によく戦ったな" },
            { 738206192, "褒めてるつもり？" },
            { 738206193, "言わせるな　気分はどうだ？" },
            { 738206194, "精神4で身体は10　ボコ殴りされた女子にしては　すこぶる快調よ" },
            { 738206195, "サイラの力を吸収したことで　体力や傷も回復したな" },
            { 738206196, "言われなくても知ってるよ" },
            { 738206197, "以前より『レベルアップ』もしたみたいだ" },
            { 738206198, "何か変化がないか試してみよう" },
            { 738206199, "凄いね！　お互い強化されたみたい" },
            { 738206200, "どうしてだ？" },
            { 738206201, "サイラについてたお前みたいなのが" },
            { 738206202, "融合したからじゃないの？" },
            { 738206203, "あぁ！　そうだな" },
            { 738206204, "おかげで封印も一部解けたみたいだ　感謝するよ" },
            { 738206205, "お前がほかにもいるとは思わなかったけど" },
            { 738206206, "確かに驚きだ！　やつらがいかに残忍かわかる" },
            { 738206207, "拘束しただけでなく　俺の身体まで分断していたとは" },
            { 738206208, "何が起きたにせよ" },
            { 738206209, "この地獄 で生き延びる確率が上がったのは間違いないね" },
            { 738206210, "何をして彼女たちを怒らせたの？" },
            { 738206211, "理性に訴えただけだ" },
            { 738206212, "対立を解決しようとしたが　聞く耳を持たなかった" },
            { 738206213, "その飽くなき欲求がこの狂気をもたらしたんだ" },
            { 738206214, "その怒ってる姿は間近で見たからね" },
            { 738206215, "あれは夢に出てきそう" },
            { 738206216, "だが未来は明るい！" },
            { 738206217, "酒場でオーデンに報告して報酬を受け取ろうじゃないか" },
            { 738206218, "へぇ" },
            { 738206219, "どうした？" },
            { 738206220, "『田舎娘』って呼ばないのね" },
            { 738206221, "成長したのさ" },
            { 738206222, "タンタの恵みを！　あんたは英雄だ！" },
            { 738206223, "なんでわかったの？" },
            { 738206224, "空を見たんだ　タンタが死ぬときは天が暗くなると言われている" },
            { 738206225, "どうぞ　英雄への捧げものです" },
            { 738206226, "えぇと……" },
            { 738206227, "好意を無駄にするな　受け取れ" },
            { 738206228, "（小声でカフに対して）いらないんだけど" },
            { 738206229, "一番の鶏です" },
            { 738206230, "ありがとう" },
            { 738206231, "ひとり倒して家畜の献上か" },
            { 738206232, "四人倒したときは何がもらえるか想像できるか？" },
            { 738206233, "興味ない" },
            { 738206234, "家畜場とか" },
            { 738206235, "お断り" },
            { 738206236, "村にお前の名前がつくとか" },
            { 738206237, "それは魅力的　でもほかのタンタたちを殺す気はない" },
            { 738206238, "危うく死にそうだったし　（鶏を見て）さて　どこに置こうか" },
            { 738206239, "『魔法使いのおばさん』じゃない" },
            { 738206240, "今後は本を表紙で判断しないでね" },
            { 738206241, "（困惑して）誰がそんなことする？" },
            { 738206242, "（ジョークがわからないと知り）図書委員だったらわかると思ったんだけど――" },
            { 738206243, "司書だ！" },
            { 738206244, "つまり勝ったの　貧弱な娘のほうがね" },
            { 738206245, "どうやら見た目よりは強いみたいだな" },
            { 738206246, "もう少し肉をつけたほうがいいと思うが" },
            { 738206247, "大変だったよ" },
            { 738206248, "（悲しげに）それはそうだろ　サイラは……最強だったからな" },
            { 738206249, "武においては天才だった　彼女に私の武器を使ってもらえたのは誇りだ" },
            { 738206250, "（少し申し訳なさそうに）親友だったんだね――" },
            { 738206251, "（気遣いに感謝し）遥か昔のことさ　それよりこの勝利は一時的だ" },
            { 738206252, "タンタたちは深い絆で結ばれている　対立したことがあっても" },
            { 738206253, "その精神は古から繋がっている" },
            { 738206254, "あたしが金持ちになるか占えるってこと？" },
            { 738206255, "宝くじ当てたいんだけど" },
            { 738206256, "（無視して）四弦の楽器のように　ともに旋律を奏でた" },
            { 738206257, "ひとつ切れると　その振動は残りの弦も揺るがす" },
            { 738206258, "（弦がひとつ切れるような演技をして）トゥワーン！" },
            { 738206259, "（一息空けて）今後どうなるかわからないが　きっと反響が起きるだろう" },
            { 738206260, "どんな反響？" },
            { 738206261, "それは予想できないが　その内わかることになるだろう" },
            { 738206262, "お前の世界では　鶏の抱き方も教えないのか？" },
            { 738206263, "必要としないスキルだからね　てか　あげるよ" },
            { 738206264, "酒場ではお前の祝宴を開いているみたいだ" },
            { 738206265, "私は嫌いだが　お前は楽しんできたらいいんじゃないか　タンタ・スレイヤー" },
            { 738206266, "祝勝パレードの気分を盛り下げてくれてありがとう" },
            { 738206267, "パレードもして欲しいのか？" },
            { 738206268, "もう行くね" },
            { 738206269, "（鶏に向かって）聞いたか？　パレードまで望むとは……我儘だな" },
            { 738206270, "何これ？！" },
            { 738206271, "ジョヘッディが言ったとおりだ" },
            { 738206272, "サイラを倒したことで　今度はプラーヴの怒りを招いてしまったようだ" },
            { 738206273, "あたしのせいって言うの？！　そんな訳ないでしょ！" },
            { 738206274, "お前がやったことは正しい" },
            { 738206275, "この展開は誰にも予想できなかった" },
            { 738206276, "クソったれ！　なんでよ！" },
            { 738206277, "オーデン！" },
            { 738206278, "ここにいたら死ぬよ　早く高台に" },
            { 738206279, "仮）　まだ下に人が残ってるの" },
            { 738206280, "仮）　私が助けに行く" },
            { 738206281, "仮）　わかった　評議堂で待ってる" },
            { 738206282, "さっきまでは普通の――" },
            { 738206283, "人だった" },
            { 738206284, "でも今は……どうしてこんな酷いことが" },
            { 738206285, "仮）　ぐうっ！" },
            { 738206286, "仮）　しくった・・・" },
            { 738206287, "数が多すぎる！" },
            { 738206288, "やるんだ" },
            { 738206289, "あれを見たら殺せないよ" },
            { 738206290, "やれ！　戦って浸食のない場所に向かうんだ" },
            { 738206291, "やつらはブレイクの外に出られない ！" },
            { 738206292, "傷ましいな　ブレイクに侵されている" },
            { 738206293, "生き続けるのは苦痛だろう　早く解放してやれ" },
            { 738206294, "それだけはやらない　まだ人である彼らを殺すなんて！" },
            { 738206295, "苦しみを引き延ばすだけだぞ" },
            { 738206296, "浸食が手遅れになる前に止めることができれば" },
            { 738206297, "まだ希望はあるでしょ" },
            { 738206298, "深い傷だな" },
            { 738206299, "大丈夫　早くここを出よう" },
            { 738206300, "助かったな　ここはもうブレイクの影響を受けていない" },
            { 738206301, "もう少しだ　フレイ" },
            { 738206302, "平気　ただ少し……疲れた" },
            { 738206303, "あと少しだ　ここならもうブレイクボーンに遭遇する危険もない" },
            { 738206304, "みんな……予想してなかったよね" },
            { 738206305, "あぁ　できるはずがない" },
            { 738206306, "疲れた" },
            { 738206307, "進むんだ" },
