            { 738206576, "4. Find Breakbob" },
            { 738206577, "What's Going On?" },
            { 738206578, "Breakbob & Auden" },
            { 738206579, "4. Learn about Sila" },
            { 738206580, "4. Head to Sila's Castle" },
            { 738206581, "Head to Sila's Castle" },
            { 738206582, "Hostile Environment" },
            { 738206583, "Breakstorm" },
            { 738206584, "Escape the Storm" },
            { 738206585, "Cuff's Advice" },
            { 738206586, "Head to the Cave" },
            { 738206587, "After the Storm" },
            { 738206588, "Breakbob's Story" },
            { 738206589, "Guards in the Way" },
            { 738206590, "Sila's Story" },
            { 738206591, "この辺りで父を見かけなかった？" },
            { 738206592, "さっきフラっと来たよ　なんで来たか忘れたみたいで" },
            { 738206593, "突然歌ったり驚いたりしていなくなったよ" },
            { 738206594, "どんな歌だったの？" },
            { 738206595, "なんだって？" },
            { 738206596, "歌よ　どんな歌だった？" },
            { 738206597, "どうして気になるの？" },
            { 738206598, "どんな歌だったかって聞いてるの" },
            { 738206599, "うーん……童謡みたいだったかな　確かこんな感じだ" },
            { 738206600, "『回れ 回れ バロウの下で』とかなんとかかんとか" },
            { 738206601, "何かピンと来る ？" },
            { 738206602, "『ピンと』の意味がわからないわ" },
            { 738206603, "この歌に何か心辺りないの？" },
            { 738206604, "そうだわ！　きっとあそこよ！" },
            { 738206605, "さすがね フレイ" },
            { 738206606, "どこのことなの？" },
            { 738206607, "農園だと思うわ　資料にバロウの樹液のことが書かれてた" },
            { 738206608, "それを取りに行ったのよ きっと" },
            { 738206609, "探そう" },
            { 738206610, "ありがとう" },
            { 738206611, "<iconChapterSumVfxAlt>さっさと図書館に向かうぞ" },
            { 738206612, "でもボブの行方も気になるよ" },
            { 738206613, "<iconChapterSumVfxAlt>どちらにせよ　サイラを倒す準備を急ごう" },
            { 738206614, "それよりサイラを倒す準備を急ごう" },
            { 738206615, "それも大事だけど" },
            { 738206616, "帰るためにはボブにトラーナの資料の解読をお願いしないと" },
            { 738206617, "それは何度も聞いた　だが俺が塔で尋ねた質問にはまだ答えていない" },
            { 738206618, "なぜそこまでしてニューヨークに帰りたいんだ？" },
            { 738206619, "あそこでは惨めだったんだろ？" },
            { 738206620, "でもここよりはマシよ　どっちの地獄を選ぶかはあたしの自由" },
            { 738206621, "それに 大切な猫を人にあげちゃったの　あたしのホーマー" },
            { 738206622, "とても後悔してる　だから帰らないと" },
            { 738206623, "なんで捨てたんだ？" },
            { 738206624, "状況が……悪かったの" },
            { 738206625, "今は良くなったのか？" },
            { 738206626, "うるさい　ただ早く迎えに行きたいの" },
            { 738206627, "田舎娘オーデンとの友情より" },
            { 738206628, "臭い飼い猫といることを望むのか？" },
            { 738206629, "ホーマーの悪口はやめて　それに臭くない" },
            { 738206630, "いつも自分の身体を舐めて清潔にしてるし……大切な家族なの" },
            { 738206631, "怒らせるつもりはなかった　しかしな……" },
            { 738206632, "いいから黙ってて　お前はあたしについてくればいいの" },
            { 738206633, "今はオーデンのあとを追って ボブの行方を探すよ" },
            { 738206634, "サイラはあとでも殺せるけど ボブがいないと帰れないからね" },
            { 738206635, "ご自由に" },
            { 738206636, "<iconChapterSumVfxAlt>あの不愉快な婆さんの言葉を真に受けていないよな？" },
            { 738206637, "不愉快はお前で十分よ" },
            { 738206638, "<iconChapterSumVfxAlt>これは一本とられたな" },
            { 738206639, "まあ……戸惑いはしたけど" },
            { 738206640, "オリヴィアの仇をとる決意は変わらない" },
            { 738206641, "<iconChapterSumVfxAlt>オリヴィアか　彼女のため立ち上がったのは誇りに思うぞ" },
            { 738206642, "ジュヌーンとは違う景色ね" },
            { 738206643, "<iconChapterSumVfxAlt>瘴気に同じものは存在しない" },
            { 738206644, "<iconChapterSumVfxAlt>その主の心が唯一無二であるようにな" },
            { 738206645, "<iconChapterSumVfxAlt>今はニューアークに帰れたときのことでも考えろ" },
            { 738206646, "ニューヨークよ" },
            { 738206647, "<iconChapterSumVfxAlt>なんでその場所が大事なんだ？" },
            { 738206648, "<iconChapterSumVfxAlt>帰りたい理由を三つ言え" },
            { 738206649, "ホーマー　秋のセントラルパーク" },
            { 738206650, "47と9番通りにあるクニッシュのお店" },
            { 738206651, "<iconChapterSumVfxAlt>クニッシュとは？" },
            { 738206652, "ポテトを生地で包んだ最高のものよ" },
            { 738206653, "マスタードと玉ねぎと一緒に食べるの　それが一番の食べ方" },
            { 738206654, "それを食べてる間は幸せで あたしの悩みもしばらく消えるの" },
            { 738206655, "<iconChapterSumVfxAlt>それは美味そうだ" },
            { 738206656, "想像もできないよ　誰か殺してもいいぐらい" },
            { 738206657, "<iconChapterSumVfxAlt>なら今かもな　気を付けろ！" },
            { 738206658, "サイラ城は…まだ見えないね" },
            { 738206659, "<iconChapterSumVfxAlt>この辺りは山が険しい" },
            { 738206660, "<iconChapterSumVfxAlt>谷のほうに回り込んで進むぞ" },
            { 738206661, "本当によく知ってるね　来たことあるの？" },
            { 738206662, "<iconChapterSumVfxAlt>…地図を見ろ" },
            { 738206663, "<iconChapterSumVfxAlt>おい　避難できそうな洞窟を見つけたぞ" },
            { 738206664, "樹を切り倒すのはやめてください！" },
            { 738206665, "<iconChapterSumVfxAlt>なにやら騒がしいな" },
            { 738206666, "あの樹のあたりからだね" },
            { 738206667, "仮）ここは通れないね" },
            { 738206668, "仮）一旦戻るか" },
            { 738206669, "しかたない　案内して" },
