            { 738206918, "主にジュヌーンに生育している自然の草花。回復薬などの材料として使える" },
            { 738206919, "摘みたて新鮮な草花。どこでもよく見かける。" },
            { 738206920, "摘みたて新鮮な草花。どこでもよく見かける。" },
            { 738206921, "摘みたて新鮮な草花。どこでもよく見かける。" },
            { 738206922, "摘みたて新鮮な草花。どこでもよく見かける。" },
