            { 738210684, "Was that a thank you!?" },
            { 738210685, "Will you be careful!?" },
            { 738210686, "I'm sorry, alright?" },
            { 738210687, "That was bad." },
            { 738210688, "I wholeheartedly agree." },
            { 738210689, "Whew..." },
            { 738210690, "<EmptyString>" },
            { 738210691, "Are you alright, Frey?" },
            { 738210692, "Uhh, just about..." },
            { 738210693, "Cuff!" },
            { 738210694, "Urgh... I'm fine..." },
            { 738210695, "Bleurgh! This is bitter as fuck!" },
