            { 738210705, "Be ready to protect yourself." },
            { 738210706, "I will—with you." },
            { 738210707, "Looks like the coast is clear." },
            { 738210708, "Let's not get careless." },
            { 738210709, "Seems we're free of any immediate danger." },
            { 738210710, "Here's hoping it stays that way." },
            { 738210711, "No monsters here, huh?" },
            { 738210712, "Were you hoping for a little exercise?" },
            { 738210713, "Our destination is close." },
