            { 738210716, "Cool." },
            { 738210717, "Nearly there, right?" },
            { 738210718, "Yes, very nearly." },
            { 738210719, "I think we're nearly there." },
            { 738210720, "Well done, me." },
            { 738210721, "Are we there yet?" },
            { 738210722, "Not long now." },
            { 738210723, "Almost there." },
            { 738210724, "Roger that." },
            { 738210725, "It's just up ahead." },
            { 738210726, "Uh-huh." },
            { 738210727, "We're still a ways off, aren't we?" },
            { 738210728, "Not too far now." },
            { 738210729, "How far now?" },
            { 738210730, "We're getting closer." },
            { 738210731, "Is it close?" },
            { 738210732, "Not really, no." },
            { 738210733, "Pick up the pace, will you?" },
            { 738210734, "Guess that means we are nowhere close." },
            { 738210735, "How about you do the legwork for a change?" },
            { 738210736, "Not something vambraces are famed for, I'm afraid." },
            { 738210737, "There's a fair way to go yet." },
            { 738210738, "Ugh, great..." },
            { 738210739, "Why is this place so far away?" },
            { 738210740, "I'm not the one who chose to go there." },
            { 738210741, "We're still fucking miles away, aren't we?" },
