            { 738210743, "Whoa! Did you see that?" },
            { 738210744, "Don't stop now!" },
            { 738210745, "I'm a human fucking tornado!" },
            { 738210746, "How delicately put." },
            { 738210747, "Quite the little burst of speed there." },
            { 738210748, "Plenty more where that came from!" },
            { 738210749, "Are you sure it's safe to run that fast?" },
            { 738210750, "Ha! You ain't seen nothing yet!" },
            { 738210751, "I could do this all day!" },
            { 738210752, "Please do." },
            { 738210753, "Wasn't even trying!" },
            { 738210754, "Yes, yes." },
            { 738210755, "I'm sure I've seen you jump higher than that." },
