            { 738210760, "One can only imagine the heady heights you might attain if you made an actual effort." },
            { 738210761, "Think you can get even higher?" },
            { 738210762, "Oh, I know I can." },
            { 738210763, "Did pretty good that time." },
            { 738210764, "Reasonably, yes." },
            { 738210765, "Gosh. Look at you go." },
            { 738210766, "I know, right?" },
            { 738210767, "Ooh, that was sweet!" },
            { 738210768, "Passable." },
            { 738210769, "You were almost flying there." },
            { 738210770, "Woo! Yeah!" },
            { 738210771, "Straight-up amazing, am I right?" },
            { 738210772, "A little modesty wouldn't hurt." },
            { 738210773, "I think we can jump a little farther than that, don't you?" },
            { 738210774, "I don't see why not." },
            { 738210775, "Feel like I could go farther, you know?" },
            { 738210776, "Put a little pep in your step!" },
            { 738210777, "A little farther, and you'll be flying." },
            { 738210778, "I'm on it." },
            { 738210779, "Piece of cake!" },
            { 738210780, "Just getting warmed up, eh?" },
            { 738210781, "You can do better than that." },
            { 738210782, "Oh, you ain't seen nothin' yet..." },
            { 738210783, "Covered some serious ground there. Nice!" },
            { 738210784, "Keep up the good work!" },
            { 738210785, "You're coming on in leaps and bounds." },
            { 738210786, "Even surprised myself there..." },
            { 738210787, "I am flying!" },
            { 738210788, "Bravo." },
            { 738210789, "Look at you go." },
            { 738210790, "I'm even better at this than I thought!" },
            { 738210791, "Phew. Just about stuck the landing there." },
            { 738210792, "You certainly can't be accused of holding back." },
            { 738210793, "I can slide even farther. I know I can." },
