            { 738210837, "A bit close for comfort..." },
            { 738210838, "Just \"a bit\"?" },
            { 738210839, "They're not coming after you, are they?" },
            { 738210840, "I rather think you're the more appetizing option." },
            { 738210841, "They're too close." },
            { 738210842, "Gotta try and get some distance." },
            { 738210843, "Damn! No use from this close!" },
            { 738210844, "Keep your distance!" },
            { 738210845, "I think you might need to be a little farther away." },
            { 738210846, "I think you might need to tell me this shit sooner!" },
