            { 738210848, "You have to get closer!" },
            { 738210849, "That won't work! You need to close the distance!" },
            { 738210850, "Ugh! I know, alright?" },
            { 738210851, "Well, that's not working." },
            { 738210852, "Too far away." },
            { 738210853, "Not quite getting there..." },
            { 738210854, "Yes. Just out of range." },
            { 738210855, "Hmm. Falling a little short..." },
            { 738210856, "Really? I hadn't noticed!" },
            { 738210857, "Shit. Farther than I thought." },
            { 738210858, "Optimism can be a curse, you know." },
            { 738210859, "That kind of magic requires more range." },
            { 738210860, "I kinda guessed that already." },
            { 738210861, "Ugh! Get the fuck back!" },
