            { 738210886, "Focus, Frey." },
            { 738210887, "Shit, fuck, shit!" },
            { 738210888, "Throwing a hissy fit won't help." },
            { 738210889, "Just wait until you're ready!" },
            { 738210890, "Ugh, I thought I overdid it!" },
