            { 738210898, "Why not? Use it while you got it, that's what I say!" },
            { 738210899, "How many we got left?" },
            { 738210900, "Not many." },
            { 738210907, "Not exactly the most sophisticated of garments..." },
            { 738210908, "Hey, it's better than nothing." },
            { 738210909, "The rallying cry of mediocrities everywhere." },
            { 738210910, "Nothing special about this cloak." },
