            { 738211006, "I'm just getting started!" },
            { 738211007, "Damn right you are!" },
            { 738211008, "We can do better than that!" },
            { 738211009, "Alright!" },
            { 738211010, "Gotta hit harder!" },
            { 738211011, "Next time, you'll see!" },
            { 738211012, "Gah! Pathetic!" },
            { 738211013, "Urgh, c'mon, again!" },
            { 738211014, "That was weak!" },
            { 738211015, "Give it another go!" },
            { 738211016, "Thoughts?" },
            { 738211017, "Not bad. For you." },
            { 738211018, "Very nicely timed!" },
            { 738211019, "Hah. Thanks." },
            { 738211020, "Fuck yeah!" },
            { 738211021, "Now try to do that every time." },
            { 738211022, "That was rather good." },
            { 738211023, "Hey, I'm just getting started!" },
            { 738211024, "Poetry in motion!" },
            { 738211025, "Keep it up!" },
            { 738211036, "Keep knocking them back!" },
            { 738211037, "With pleasure!" },
            { 738211038, "I could do this all day!" },
            { 738211039, "It would certainly seem so..." },
            { 738211040, "Think you can keep that up?" },
            { 738211041, "Just watch me!" },
            { 738211042, "Bring it, assholes!" },
            { 738211043, "Nice to see you enjoying yourself." },
            { 738211044, "That's the stuff!" },
            { 738211045, "I'm not even trying!" },
            { 738211046, "Don't stop now!" },
            { 738211047, "Gimme everything you've got!" },
            { 738211048, "C'mon! Even you've gotta be impressed by this!" },
