            { 738224366, "Guess we better turn back." },
            { 738224367, "Can't go any farther." },
            { 738224368, "No way through..." },
            { 738224369, "Think we're stuck..." },
            { 738224370, "...Dead end." },
            { 738224371, "Not sure about this..." },
            { 738224372, "It's closed..." },
            { 738224373, "Won't open..." },
            { 738224374, "Still won't open..." },
            { 738224375, "Won't be getting in this way." },
            { 738224376, "Nothing here." },
            { 738224377, "Think we're done here..." },
            { 738224378, "No-go, huh?" },
            { 738224379, "No point staying here." },
            { 738224380, "Let's try somewhere else." },
            { 738224381, "Time to look elsewhere." },
            { 738224382, "Can't get out this way." },
            { 738224383, "There's no point going any farther." },
            { 738224384, "Let's see what's over there." },
            { 738224385, "Let's head that way." },
            { 738224386, "Think I can see something over there..." },
            { 738224387, "Think there's a town over there..." },
            { 738224388, "Hey, what's that...?" },
            { 738224389, "Uh...maybe that way." },
            { 738224390, "This way!" },
            { 738224391, "I think we can get through this way." },
            { 738224392, "Looks like we're on the right track." },
            { 738224393, "There's something there..." },
            { 738224394, "Let's take a closer look." },
            { 738224395, "Hey, I see something!" },
            { 738224396, "Think we can climb it?" },
            { 738224397, "How can we get inside?" },
            { 738224398, "Hey—it's a way out." },
            { 738224399, "Let's see if we can find anyone." },
            { 738224400, "Time to go." },
            { 738224401, "Seek, and you shall find." },
            { 738224402, "Let's get a hustle on." },
            { 738224403, "Let's bounce." },
            { 738224404, "C'mon, c'mon!" },
            { 738224405, "Hey, what about this way?" },
            { 738224406, "What is it?" },
            { 738224407, "Huh, there's something written here..." },
            { 738224408, "Hey, look..." },
            { 738224409, "Where the hell are we?" },
            { 738224410, "What's this...?" },
            { 738224411, "Hey, check that out..." },
            { 738224412, "Where'd it go?" },
            { 738224413, "Where are you...?" },
            { 738224414, "What happened here?" },
            { 738224415, "Damn. Big town." },
            { 738224416, "Nothing but ruins..." },
            { 738224417, "Hey, a cave." },
            { 738224418, "Whoa. Heckuva view..." },
            { 738224419, "Look at that lake." },
            { 738224420, "Wow, that's pretty high up." },
            { 738224421, "Wow. Talk about a wide open space..." },
            { 738224422, "Pretty cramped..." },
            { 738224423, "Check out this forest." },
            { 738224424, "You see that river?" },
            { 738224425, "Whoa. Now that's what I call a waterfall." },
            { 738224426, "Yeah, looks pretty deep..." },
            { 738224427, "Pretty wild out here, huh?" },
            { 738224428, "Shit!" },
            { 738224429, "That was way too fucking close!" },
            { 738224430, "We need to get outta here!" },
            { 738224431, "C'mon! Let's go!" },
            { 738224432, "Huh? Where did you go?" },
            { 738224433, "You think you can hide from me!?" },
            { 738224434, "C'mon, quickly!" },
            { 738224435, "We don't have long!" },
            { 738224436, "Let's move!" },
            { 738224437, "Quickly, quickly, quickly, quickly!" },
            { 738224438, "What the fuck is that!?" },
            { 738224439, "What the heck is this!?" },
            { 738224440, "I'm on it!" },
            { 738224441, "This sucker's dead!" },
            { 738224442, "This isn't the right way!" },
            { 738224443, "What the hell!?" },
            { 738224444, "That was fucking tough!" },
            { 738224445, "Can't believe we actually won that one..." },
            { 738224446, "Pah. That was a cinch." },
            { 738224447, "That was pretty wild, huh?" },
            { 738224448, "Kinda noisy round here." },
            { 738224449, "Yeah, going's getting real tough." },
            { 738224450, "Bedtime..." },
            { 738224451, "Can we rest already?" },
            { 738224452, "Nobody here..." },
            { 738224453, "Better get after 'em." },
            { 738224454, "I like this place. ...Nice and lively." },
            { 738224455, "Better be quiet..." },
            { 738224456, "Damn, it's pretty dead around here." },
            { 738224457, "Something's not right..." },
            { 738224458, "Last one." },
            { 738224459, "Looks like that's it." },
            { 738224490, "My parents were. I was born here." },
            { 738224491, "Cipaler born and bred, huh?" },
            { 738224492, "Anyone my age or younger pretty much has to be." },
            { 738224493, "Sometimes. But we're not a priority down here." },
            { 738224494, "The upper city comes first. In that, and in everything else." },
            { 738224495, "That sucks..." },
            { 738224496, "<EmptyString>" },
            { 738224497, "……あ！" },
            { 738224498, "Up there's where we get our water." },
            { 738224499, "I...I've seen that already. Thank you though." },
            { 738224500, "Oh, really?" },
            { 738224501, "Alright, then. Let me show you something else." },
            { 738224502, "Oi! You!" },
            { 738224503, "Huh? You talking to me?" },
            { 738224504, "Oopsie, she's a sharp one! What's that you got there, eh?" },
            { 738224505, "Uh, this? Found it lying around outside town." },
            { 738224506, "What a funny little doll!" },
            { 738224507, "Let me swap you something for it. I'll do you a good deal, I promise!" },
            { 738224508, "Make the trade?" },
            { 738224509, "Sure." },
            { 738224510, "No way." },
            { 738224511, "Pleasure doing business with you!" },
            { 738224512, "Stop by and see me if you find any more, eh? Don't be a stranger, now!" },
            { 738224513, "Uh, sure." },
            { 738224516, "Sorry. Not today." },
            { 738224517, "Hey, do you like animals?" },
            { 738224518, "They're alright, I guess." },
            { 738224519, "Great! You'll like this, then!" },
            { 738224520, "Come on, let's go and take a closer look." },
            { 738224521, "Feeding Time" },
            { 738224522, "Just go up to one of them and hold out your hand." },
            { 738224523, "Feed the animals?" },
            { 738224524, "I'll pass." },
            { 738224525, "Sure, why not?" },
            { 738224527, "I fed this one already. Better spread the love." },
            { 738224528, "Cats here are just the same, huh?" },
            { 738224529, "Did you like that?" },
            { 738224530, "Taking it easy, huh, big fella?" },
            { 738224531, "You're a sweetie, aren't you?" },
            { 738224532, "Awww... There's a good kitty." },
            { 738224533, "Nothing wrong with a healthy appetite, I guess." },
            { 738224534, "Heh. You're dumb. But cute." },
            { 738224535, "Sorry. All outta chow." },
            { 738224536, "This guy's a mess. You don't bathe them?" },
            { 738224537, "Oh, we try. But that one just loves his mud baths." },
            { 738224538, "Heh. Fluffy..." },
            { 738224539, "Damn. You really wolfed that down, huh?" },
            { 738224540, "\"Our savior's favorite farm.\" Has kind of a ring to it...don't you think? I might put up a sign!" },
            { 738224541, "Right, I suppose it's time I showed you the upper city. It's back the way we came and up the stairs." },
            { 738224542, "Or did you want to look around a bit more first?" },
            { 738224543, "Do you feed the animals a lot?" },
            { 738224544, "Sometimes. Just to get away from work, you know." },
            { 738224545, "Oh. I thought maybe you worked here." },
            { 738224546, "Hah, no! That's more responsibility than I'm cut out for." },
            { 738224547, "Like I said, this is the graveyard." },
            { 738224548, "There's so many of them..." },
            { 738224549, "Yeah. Well, if they're dead, they're down there..." },
            { 738224550, "This gate..." },
            { 738224551, "It's been closed for years because of the Corruption." },
            { 738224552, "You used to be able to get to Praenost that way." },
            { 738224553, "Shall we make a move? There's more I want to show you." },
            { 738224554, "Oh, can I ask you something?" },
            { 738224555, "Your...powers. Could you give me a quick demonstration?" },
            { 738224556, "Absolutely not! You're not some...street performer!" },
            { 738224557, "Look, I'm sorry. But they're not for show." },
            { 738224558, "Ah, really? I was hoping you'd give me another look..." },
            { 738224559, "But I guess I've seen enough. Athia's as good as saved already!" },
            { 738224560, "How many fucking times do I have to tell you? I'm not. Your. Savior." },
            { 738224561, "So, this is where the rich folks live." },
            { 738224562, "Yep. And they get the best food, the nicest clothes, and the safest part of the city to themselves." },
            { 738224563, "They get to run everything just because of who they are! Best not to think about it..." },
            { 738224564, "Ahh, the accident of birth. Curse you, cruel fate!" },
            { 738224565, "This is the Tower of—oh, sorry. I forgot." },
            { 738224566, "Hey, don't worry about it. Let's maybe not go in for the full tour, though." },
            { 738224567, "Frey! Not that way! Over here!" },
            { 738224568, "Alright, alright! No need to shout. Geez..." },
            { 738224569, "What business have you with the Council?" },
            { 738224570, "You shouldn't be here. Go on, go!" },
            { 738224571, "It's her..." },
            { 738224572, "Ugh, don't even look at her." },
            { 738224573, "That boy is here again..." },
            { 738224574, "Ignore him. He'll clear off soon enough." },
            { 738224575, "Do you want me to call the guards?" },
            { 738224576, "Only if she does something." },
            { 738224577, "Well, of course she will!" },
            { 738224578, "We'll see, dear, we'll see." },
            { 738224579, "What business does someone like that have in this part of the city?" },
            { 738224580, "Can she really be trusted?" },
            { 738224581, "It's not our place to question the infinite wisdom of the Council!" },
            { 738224582, "Well, if outsiders come in and cause problems, we just have t—" },
            { 738224583, "Shhh! She'll hear you!" },
            { 738224584, "I hope nothing else awful happens..." },
            { 738224585, "Are you lost? You do know this is the upper city?" },
            { 738224586, "Perhaps you should try going that way?" },
            { 738224587, "Sorry, can you leave her alone?" },
            { 738224588, "She's not used to strangers." },
            { 738224589, "What about our tour? There's so much still to see." },
            { 738224590, "I don't need his stupid fucking tour." },
            { 738224591, "Where the 'eck are ya? Get 'ere! Now!" },
            { 738224592, "Oh no! It's the boss!" },
            { 738224593, "Don't tell me the feeling's mutual? That feckless young idiot? Come on!" },
            { 738224594, "What could you possibly see in—" },
            { 738224595, "Better him than a smart-ass \"vambrace.\"" },
            { 738224596, "Thank you, Frey. Really! Thank you!" },
            { 738224597, "Pilo's such a silly man!" },
            { 738224598, "His boss is always angry with him!" },
            { 738224599, "Do you know what this place is called? \"Finders Keepers.\"" },
            { 738224600, "A girl named Olevia told me." },
            { 738224601, "Thanks for being a sport about the little ones, Frey." },
            { 738224602, "They were so happy you went to see them. You'll go and say hello again, won't you?" },
            { 738224603, "I doubt the people of the lower city have very much of anything to spare." },
            { 738224604, "Okay. So we hit the upper city." },
            { 738224605, "Well, I'm not sure how much generosity we'll meet with there." },
            { 738224606, "We don't know if we don't try. Let's go." },
            { 738224607, "We need to find somebody with kitty chow to spare..." },
            { 738224608, "So, what kind of flowers do you need?" },
            { 738224609, "I'm ever so sorry to have to bother you with this, Frey." },
            { 738224610, "But...well, it's been a struggle putting together a nice garland of anything lately." },
            { 738224611, "It would be wonderful if you could bring back anything you happen to find outside town." },
            { 738224612, "No problem. I'm on it." },
            { 738224614, "Those flowers all used to grow round here, you know. You shouldn't have to go too far to find them." },
            { 738224615, "Frey, Frey! Hello!" },
            { 738224616, "Hey, kid. You said some bench was broken?" },
            { 738224617, "It is! The metal thingies that hold it together all snapped." },
            { 738224618, "Rusted away, huh? Guess we'll need to find some new ones." },
            { 738224619, "Aren't raw materials something of a rarity at the moment?" },
            { 738224620, "They sure are. Thanks to a certain somebody." },
            { 738224621, "Ahem..." },
            { 738224622, "You might be able to find something suitable in Praenost, I suppose." },
            { 738224623, "Cool. Let's go see what we can rustle up." },
            { 738224624, "Let's see what we can find to replace those bench parts in Praenost." },
            { 738224625, "Hey, could I ask a favor?" },
            { 738224626, "Well, if it isn't Frey herself." },
            { 738224627, "Come to pet my little darling, have you?" },
            { 738224628, "Not today. I was wondering if she might be able to spare some food for a friend." },
            { 738224629, "Guy I know has a cat who could really use some." },
            { 738224630, "Gosh, sounds like quite the pickle. One minute..." },
            { 738224631, "There you go." },
            { 738224632, "Wow. This is tons. Thanks!" },
            { 738224633, "Not at all. I'm sure you'd do the same for me." },
            { 738224634, "Cat people are good people." },
            { 738224635, "Vacuous nonsense." },
            { 738224636, "Hope that food I gave you goes down well." },
            { 738224637, "Here. You need some cat food, right?" },
            { 738224638, "Wow, that's loads! Thanks so much!" },
            { 738224639, "Don't thank me. It was the guy in the upper city—the one who likes to sit out on the street with his cat. You know him?" },
            { 738224640, "Of course. I'll have to go and say thank you!" },
            { 738224641, "You do that. Just get back to your kittens first." },
            { 738224642, "Ooh, I almost forgot! Alright, say thanks to Pilo, too!" },
            { 738224659, "I think that's all the flowers the lady asked for, right?" },
            { 738224660, "Let's go give her the good news." },
            { 738224662, "Hand over the flowers?" },
            { 738224663, "No." },
            { 738224664, "Sure." },
            { 738224675, "Hey, I brought you some flowers. This is the kind of thing you had in mind?" },
            { 738224676, "Oh, dear! You didn't have to go to all that trouble, honestly!" },
            { 738224677, "Ah, it was nothing." },
            { 738224678, "Now I can make a lovely garland to take up to the mausoleum." },
            { 738224679, "Mustn't forget to thank young Pilo too when I see him. He said he'd try and find some for me as well..." },
            { 738224680, "What do you think? Usable?" },
            { 738224681, "Oh, no. Far too old. Won't last five minutes." },
            { 738224682, "No good, huh?" },
            { 738224683, "Far too small. We're trying to fix a bench, remember?" },
            { 738224684, "Ugh, this is more of a hassle than I thought it would be." },
            { 738224685, "Close. But just not quite big enough." },
            { 738224686, "Dang. Thought we had it there." },
            { 738224687, "I think that'll do it, yes." },
            { 738224688, "Nice. Alright, back to Cipal." },
            { 738224689, "Here, kid. This'll work, right?" },
            { 738224690, "Amazing! You're the best, Frey!" },
            { 738224691, "Don't mention it. Is there somebody who can do the actual fixing for you?" },
            { 738224692, "I'll get my dad to do it!" },
            { 738224693, "Oh, what about Pilo, though?" },
            { 738224694, "Don't worry. I'll tell him you're all good now." },
            { 738224695, "Thanks! See ya!" },
            { 738224696, "Sorry I'm late, everyone!" },
            { 738224697, "Huh?" },
            { 738224698, "Uh, sorry. I kinda...did everything for you." },
            { 738224699, "Wanted to help out, you know?" },
            { 738224700, "Sorry for running off like that." },
            { 738224701, "And...they all said to say thanks to you." },
            { 738224702, "Forgive me for interrupting." },
            { 738224703, "And well, all the spare string was used up in the restoration efforts, so..." },
            { 738224704, "<EmptyString>" },
            { 738224705, "You really do have remarkably questionable taste." },
            { 738224706, "Well, he's not a total asshole, for a start." },
            { 738224707, "Thanks! We should do that again sometime." },
            { 738224708, "Oh, now that is a shame. Ah well, maybe next time." },
            { 738224709, "Uh... Not in the trading mood, thanks." },
