            { 738231901, "Bow before the might of the Tantas!" },
            { 738231902, "The demon is laid low at last!" },
            { 738231903, "Pity. I had hoped you might amuse me longer..." },
            { 738231904, "Victory is mine!" },
            { 738231905, "Have you finally decided to accept your fate?" },
            { 738231906, "The time for repentance is long since passed!" },
            { 738231907, "There is nowhere for you to hide!" },
            { 738231908, "None have ever escaped this prison!" },
            { 738231909, "Run, if you wish. It will do you no good!" },
            { 738231910, "You will find no refuge here!" },
            { 738231911, "The wicked cannot hope to assail what is pure!" },
            { 738231912, "Ha! Pitiful!" },
            { 738231913, "Useless, worthless! You will never touch me!" },
            { 738231914, "Guilty as charged!" },
            { 738231915, "Justice is served!" },
            { 738231916, "None shall be suffered to break the laws of Athia!" },
