            { 738232032, "This land is all but dead already." },
            { 738232033, "Why do you continue to resist the inevitable?" },
            { 738232034, "You would never have come this far without me!" },
            { 738232035, "Well, you'd have been pretty screwed without my help, too." },
            { 738232036, "No point firing at him blindly..." },
            { 738232037, "Gotta hit him where it hurts!" },
            { 738232038, "That's his weak spot!" },
            { 738232040, "There! His heart!" },
            { 738232042, "I've gotta get up there! But how..." },
            { 738232044, "Useless fools." },
            { 738232046, "Are you finally ready to succumb?" },
            { 738232048, "You are no match for the likes of me." },
            { 738232052, "Bothersome gnat!" },
            { 738232054, "How are you still alive!?" },
            { 738232056, "Ngh... Damn you..." },
