            { 738235952, "Guide me, Olas!" },
            { 738235953, "Found you! Get her! Now!" },
            { 738235954, "She's here! We need to get her back to the Tower!" },
            { 738235955, "The escapee! Don't let her get away!" },
            { 738235965, "Guard" },
