            { 738236200, "Yes. Fascinating stuff." },
            { 738236206, "Sorry, Frey...but this is where we part ways." },
            { 738236207, "Milia: Devotion and Departure" },
            { 738236208, "A junior guard officer whose greatest pride lies in her sacred duty—the protection of the people of Cipal.\n\nShe stands tall at the gate over which she..." },
            { 738236210, "Wallace: The Merry Minstrel" },
            { 738236211, "A bard who has begun to perform again, motivated by a newfound purpose.\n\nHis new song is a celebratory ode to Cipal, though those keen of ear will hea..." },
            { 738236213, "Eleph: The Burden of Vengeance" },
            { 738236214, "A confused young boy who no longer knows what to make of the woman who killed his father, but saved the city.\n\nWhile he can't quite let go of his hatr..." },
            { 738236216, "Dammit, Frey!" },
            { 738236217, "Damn you, Frey!" },
            { 738236218, "Get the fuck back here, Frey!" },
            { 738236219, "Where the fuck are you, Frey?" },
            { 738236220, "Dammit, Frey!" },
            { 738236221, "Damn you, Frey!" },
            { 738236222, "Get the fuck back here, Frey!" },
            { 738236223, "Where the fuck are you, Frey?" },
            { 738236224, "Dammit, Frey!" },
            { 738236225, "Damn you, Frey!" },
            { 738236226, "Get the fuck back here, Frey!" },
            { 738236227, "Where the fuck are you, Frey?" },
            { 738236228, "You think you can win against me?" },
            { 738236229, "Of course I can, you lying sack of shit." },
            { 738236230, "I never lied to you. Not once." },
            { 738236231, "I stand by what I said." },
            { 738236232, "Without me, you are nothing." },
            { 738236233, "All I ever did was tell you what you wanted to hear." },
            { 738236234, "Okay, so you're a gaslighting sack of shit. And don't act like you did me any favors." },
            { 738236235, "Without me you'd still be collecting dust in a pawn shop. You. Needed. Me." },
            { 738236236, "Be careful what you wish for!" },
            { 738236237, "Alright, time to shut your ass up for good." },
            { 738236238, "Shit!" },
            { 738236239, "How many of these fuckers are there?" },
            { 738236240, "I'll draw them away!" },
            { 738236241, "You try to get to his heart!" },
            { 738236242, "<EmptyString>" },
            { 738236243, "Where the hell is his fucking heart?" },
            { 738236244, "Get the fuck outta my way!" },
            { 738236245, "<EmptyString>" },
            { 738236246, "Get the hell away from me!" },
            { 738236247, "There it is!" },
            { 738236248, "Ugh, gimme a break!" },
            { 738236249, "I'm on it!" },
            { 738236250, "Your ass is ours!" },
            { 738236251, "So much for my challenge..." },
            { 738236252, "And so our story ends..." },
            { 738236253, "Just give up! Without my powers, you're nothing!" },
            { 738236254, "The tainted bloodline of the Tantas ends here!" },
            { 738236255, "You would be funny if you weren't so pathetic." },
            { 738236256, "That must be his heart!" },
            { 738236257, "Alright, now we know where to hit him." },
