            { 738236372, "<Unknown67> [<Unknown71>/<Unknown72>]" },
            { 738236373, "Whoa! What the fuck was that?" },
            { 738236374, "Oh, one of my...talents, if you will." },
            { 738236375, "Hmm... It seems like there's a small settlement up ahead. Perhaps we can rest there." },
            { 738236376, "And you know that how? What are you?" },
            { 738236377, "The extent of my abilities is nigh on limitless. I am a vambrace, after all." },
            { 738236378, "Uh-huh." },
            { 738236379, "Well? Don't just stand there!" },
            { 738236380, "I need to figure out how to control you. You know—make you do your badass thing whenever I want." },
            { 738236381, "You don't control me! I am not your toy!" },
            { 738236382, "I will aid you of my own free will, not when you command me to \"do my badass thing.\"" },
            { 738236383, "Yeah? Well, why don't you use your \"free will\" to unbond us then?" },
            { 738236384, "I would if I could, believe me..." },
            { 738236385, "<EmptyString>" },
            { 738236386, "<EmptyString>" },
            { 738236387, "<EmptyString>" },
            { 738236388, "<EmptyString>" },
            { 738236389, "<EmptyString>" },
            { 738236390, "Any bright ideas?" },
            { 738236391, "Yeah! Make this fucker let go!" },
            { 738236392, "But you'll die if you fall from up here!" },
            { 738236393, "<EmptyString>" },
            { 738236394, "I'm gonna die anyway, asshole!" },
            { 738236395, "<EmptyString>" },
            { 738236396, "<EmptyString>" },
