            { 738242367, "Well, let's do our level best to find out, shall we?" },
            { 738242368, "All these years..." },
            { 738242369, "I never knew..." },
            { 738242370, "You'd be better off dead!" },
            { 738242371, "Go ahead, jump!" },
            { 738242372, "Well, Homer, I'm back." },
            { 738242373, "Where do we go now...?" },
