            { 738243148, "Found mainly near Cipal." },
            { 738243149, "Found mainly in Praenost, most commonly near cliffs, where it is thrust up from the depths in which it is formed." },
            { 738243150, "Mainly found in Avoalet, most commonly near bodies of water such as rivers and lakes." },
            { 738243151, "Mainly found in Visoria, most commonly near large rocks jutting up from the earth." },
            { 738243152, "Mainly found in Junoon, most commonly in areas rich in vegetation." },
