            { 738246404, "<EmptyString>" },
            { 738246405, "Surrender!" },
            { 738246406, "Witness true power!" },
            { 738246407, "Cower before me!" },
            { 738246408, "<EmptyString>" },
            { 738246409, "<EmptyString>" },
            { 738246410, "<EmptyString>" },
            { 738246411, "There is no escape!" },
            { 738246412, "You go no further!" },
            { 738246413, "Piteous vermin!" },
            { 738246414, "Suffer!" },
            { 738246415, "Those who give shall be rewarded!" },
            { 738246416, "Death is nothing to fear!" },
            { 738246417, "<EmptyString>" },
            { 738246418, "<EmptyString>" },
            { 738246419, "Come, faithful Rheddig!" },
            { 738246420, "Heed my call!" },
            { 738246421, "Behold the power of Rheddah!" },
            { 738246422, "Hurt me if you can!" },
            { 738246423, "<EmptyString>" },
            { 738246424, "<EmptyString>" },
            { 738246425, "<EmptyString>" },
            { 738246426, "<EmptyString>" },
            { 738246427, "<EmptyString>" },
            { 738246428, "<EmptyString>" },
            { 738246429, "<EmptyString>" },
            { 738246430, "<EmptyString>" },
            { 738246431, "<EmptyString>" },
            { 738246432, "<EmptyString>" },
            { 738246433, "<EmptyString>" },
            { 738246434, "<EmptyString>" },
            { 738246435, "<EmptyString>" },
            { 738246436, "SUCH...POWER...!" },
            { 738246437, "<EmptyString>" },
            { 738246438, "NGARRRGH! DIE!!!" },
            { 738246439, "TREMBLE!" },
            { 738246440, "<EmptyString>" },
            { 738246441, "<EmptyString>" },
            { 738246442, "<EmptyString>" },
            { 738246443, "<EmptyString>" },
            { 738246444, "<EmptyString>" },
            { 738246445, "<EmptyString>" },
            { 738246446, "H-HOWWW!?" },
            { 738246447, "<EmptyString>" },
            { 738246448, "N-NOOO!" },
            { 738246449, "<EmptyString>" },
            { 738246450, "<EmptyString>" },
            { 738246451, "<EmptyString>" },
            { 738246452, "<EmptyString>" },
            { 738246453, "<EmptyString>" },
            { 738246454, "<EmptyString>" },
            { 738246455, "Now, on with the Gloaming!" },
            { 738246456, "Hah! Is that it?" },
            { 738246457, "Do not disappoint me!" },
            { 738246458, "<EmptyString>" },
            { 738246459, "<EmptyString>" },
            { 738246460, "HOW DARE YOU!?" },
            { 738246461, "<EmptyString>" },
            { 738246462, "IMPOSSIBLE!" },
            { 738246463, "<EmptyString>" },
            { 738246464, "<EmptyString>" },
            { 738246465, "<EmptyString>" },
            { 738246466, "<EmptyString>" },
            { 738246467, "<EmptyString>" },
            { 738246468, "<EmptyString>" },
            { 738246469, "<EmptyString>" },
            { 738246470, "ALL SHALL BE DESTROYED!" },
            { 738246471, "<EmptyString>" },
            { 738246472, "Watch out for that whirlwind!" },
            { 738246473, "Yeah, thanks!" },
            { 738246474, "Look out—whirlwind!" },
            { 738246475, "I can see it, thanks!" },
            { 738246478, "Fuck! What now!?" },
            { 738246479, "Bit smarter than your garden-variety Breakbeast, isn't it?" },
            { 738246480, "Okay... This might be slightly harder than I thought..." },
            { 738246481, "I did say it was suicide..." },
            { 738246482, "You haven't lost your nerve, have you?" },
            { 738246483, "Like hell I have!" },
            { 738246485, "Need to get rid of that barrier!" },
            { 738246486, "Rather a tall order when your magic seems to bounce right off it..." },
            { 738246487, "This is getting us nowhere!" },
            { 738246488, "Yes, it does seem rather hopeless. Any bright ideas?" },
            { 738246489, "Dammit. If only I could break through that barrier!" },
            { 738246490, "Certainly an option. As is getting the hell out of here..." },
            { 738246491, "I am NOT leaving these people behind." },
            { 738246492, "So, what's the plan?" },
            { 738246493, "We strike together!" },
            { 738246494, "It's the only way to break through the creature's shield!" },
            { 738246495, "Alright. Let's go to work!" },
            { 738246496, "It's working!" },
            { 738246497, "Now, Thalia!" },
            { 738246498, "Alright!" },
            { 738246499, "It seems we have our solution!" },
            { 738246500, "You're ours now, asshole!" },
            { 738246501, "This is far from over yet!" },
            { 738246502, "Fucking shield!? Again!?" },
            { 738246503, "Then we break it. Again." },
            { 738246504, "...Yeah. Sounds like a plan." },
            { 738246505, "Look out!" },
            { 738246506, "Shit! Better try to not get fried!" },
            { 738246507, "Fireball!" },
            { 738246508, "Gonna get barbecued at this rate..." },
            { 738246509, "We must escape the flames!" },
            { 738246510, "Guy's not messing around..." },
            { 738246511, "We're not getting anywhere near that!" },
            { 738246512, "Fall back for now!" },
            { 738246513, "Lightning! Be careful!" },
            { 738246514, "Lightning, too!? Geez..." },
            { 738246515, "Move!" },
            { 738246516, "Faster than lightning? Uh...okay..." },
            { 738246517, "はぁぁっ！" },
            { 738246519, "Enough!" },
            { 738246521, "あああ！" },
            { 738246523, "HA HA HA HAAA! I AM INVINCIBLE!" },
            { 738246524, "Uh...something tells me he's not gonna go down easy." },
            { 738246525, "Come! Entertain me!" },
            { 738246526, "Yeah, yeah. Yap while you can." },
            { 738246527, "We'll soon silence him." },
            { 738246528, "Cinta! Cover me!" },
            { 738246529, "By all means." },
            { 738246530, "I'm right behind you, Thalia." },
            { 738246531, "Alright!" },
            { 738246532, "Run, little ones!" },
            { 738246533, "Ugh, what now!?" },
            { 738246534, "Thalia! Move!" },
            { 738246535, "Oh shit oh shit oh shit..." },
            { 738246536, "Look out!" },
            { 738246537, "The wings... He's doing it again!" },
            { 738246538, "Must you!? Really!?" },
            { 738246539, "ハーッハッハッハッハッハ！" },
            { 738246540, "What's that light...?" },
            { 738246541, "Best avoided, I'd say!" },
            { 738246542, "That ball of light again!" },
            { 738246543, "Steer clear!" },
            { 738246544, "Eyes up, Thalia!" },
            { 738246545, "Shit—okay!" },
            { 738246546, "Come! Show me the \"power\" of Athia!" },
            { 738246547, "Don't let him get to you!" },
            { 738246548, "Never rains but it pours, huh?" },
            { 738246549, "We don't have time for this!" },
            { 738246550, "Do your worst, Tanta!" },
            { 738246551, "Great. The shield again." },
            { 738246552, "But now we know how to break it!" },
            { 738246553, "Wh—!? How!?" },
            { 738246554, "That did the trick!" },
            { 738246555, "Quickly, then!" },
            { 738246556, "What the hell just happened...?" },
            { 738246557, "I'd say the power is running away with him..." },
            { 738246558, "Someone has completely lost their shit..." },
            { 738246559, "Then let us use that against him!" },
            { 738246560, "He seems...scarier than before..." },
            { 738246561, "And stupider. He's lost all sense of reason. Use that against him." },
            { 738246562, "He appears to have lost his mind entirely..." },
            { 738246563, "Let's hope that means he's forgotten how to fight..." },
            { 738246564, "He won't be coming back from this, surely?" },
            { 738246565, "Yeah, guy seems pretty far gone..." },
            { 738246566, "Whatever's about to happen is definitely bad..." },
            { 738246567, "Agreed. Protect yourself!" },
            { 738246568, "What the HELL was that!?" },
            { 738246569, "I do not know. But it must have cost him dearly..." },
            { 738246570, "Thalia! He's going to do it again!" },
            { 738246571, "Shit! Better get out of the way!" },
            { 738246572, "Is he even aiming anymore!?" },
            { 738246573, "You know what they say—throw enough...stuff, and something's bound to stick." },
            { 738246574, "Those...spine things on his back are glowing!" },
            { 738246575, "Yes. And they look like they'd hurt..." },
            { 738246576, "He's aiming this way!" },
            { 738246577, "Then move!" },
            { 738246578, "We're wearing him down!" },
            { 738246579, "I'm pretty worn down, too, at this point..." },
            { 738246580, "He's almost done!" },
            { 738246581, "Then we must press the advantage!" },
            { 738246582, "あああぁぁっ！" },
            { 738246583, "Begone!" },
            { 738246584, "うりぁああ！" },
            { 738246585, "You're fucking done!" },
            { 738246586, "Here comes...something..." },
            { 738246587, "Brace yourself!" },
            { 738246588, "What is this...?" },
            { 738246589, "Whatever it is, I think we need to stand back..." },
            { 738246590, "I don't think that glow is a good glow..." },
            { 738246591, "Fall back!" },
            { 738246592, "He's building up to something!" },
            { 738246593, "Roger that!" },
            { 738246594, "Something nasty's coming!" },
            { 738246595, "Protect yourself!" },
            { 738246596, "Shitshitshitshitshit!" },
            { 738246597, "I think this is one of those \"move or die\" moments..." },
            { 738246598, "And when do you Athians propose to start trying?" },
            { 738246599, "Can it, asshole!" },
            { 738246600, "Ignore his taunts!" },
            { 738246601, "He seems to be rather embracing his beastly side." },
            { 738246602, "Oh, you think!?" },
            { 738246603, "Two fists are better than one, huh?" },
            { 738246604, "They certainly seem to be!" },
            { 738246605, "Perfect!" },
            { 738246606, "Yeah—that was pretty perfect, huh?" },
