            { 738246660, "Oh yeah? Just watch me!" },
            { 738246661, "Enemies!" },
            { 738246662, "Enemies!" },
            { 738246663, "C'mon, Cinta!" },
            { 738246664, "I'm right behind you." },
            { 738246665, "Thalia!" },
            { 738246666, "With you all the way!" },
