            { 738246764, "<EmptyString>" },
            { 738246765, "<EmptyString>" },
            { 738246781, "Ten out of ten?" },
            { 738246782, "Ten out of ten." },
            { 738246783, "Cue applause!" },
            { 738246784, "Very well done." },
            { 738246785, "That was impressive." },
            { 738246786, "Couldn't have done it without you!" },
            { 738246827, "Look out!" },
            { 738246828, "Thalia!" },
            { 738246829, "You're safe!" },
            { 738246830, "はっ！" },
            { 738246831, "Stay back!" },
            { 738246832, "Oh no, you don't!" },
            { 738246833, "Thanks!" },
            { 738246834, "It was nothing." },
            { 738246835, "Whoa. Nice one." },
            { 738246836, "Keep your guard up!" },
            { 738246837, "Too slow." },
