            { 738247585, "RETURN" },
            { 738247586, "The story of \"In Tanta We Trust\" takes place after the events of Forspoken.\n\n\nWe recommend completing the main game before playing this add-on content..." },
            { 738247588, "Well, whatever it is, I say we take advantage and get the hell outta here." },
            { 738247589, "<EmptyString>" },
            { 738247596, "Nice!" },
            { 738247597, "That was rather remarkable." },
            { 738247598, "Hell yeah!" },
            { 738247599, "Not too shabby." },
            { 738247600, "There it is!" },
            { 738247601, "Indeed..." },
            { 738247602, "That was our best yet!" },
            { 738247603, "Heh! Kinda was, huh?" },
            { 738247604, "All yours, Cinta!" },
            { 738247605, "With pleasure!" },
            { 738247606, "For Athia!" },
            { 738247607, "I cannot...just yet..." },
            { 738247608, "Please and thank you!" },
            { 738247609, "Don't mind if I do!" },
            { 738247610, "Begone, interlopers!" },
            { 738247611, "I must gather my strength..." },
            { 738247612, "Cinta!" },
            { 738247613, "They won't see this coming!" },
            { 738247614, "Let's end this!" },
            { 738247615, "Give me a moment!" },
            { 738247616, "Ready when you are!" },
            { 738247617, "Many thanks!" },
            { 738247618, "I'll make this quick!" },
            { 738247619, "I'm a little tied up at the moment..." },
            { 738247620, "Ready for you, Cinta!" },
            { 738247621, "You will pay for your cruelty!" },
            { 738247622, "This is over." },
            { 738247623, "Not right now..." },
            { 738247624, "You're up, Cinta!" },
            { 738247625, "It's about time!" },
            { 738247626, "I'll slash you to ribbons!" },
            { 738247627, "One moment, Thalia!" },
            { 738247628, "A little help over here?" },
            { 738247629, "Absolutely." },
            { 738247630, "I thought you'd never ask!" },
            { 738247631, "If I could just... Hold on!" },
            { 738247632, "You're gonna pay!" },
            { 738247633, "You guys are so dead." },
            { 738247634, "You're outta here!" },
            { 738247635, "Die already!" },
            { 738247636, "Hasta la vista!" },
            { 738247637, "Boom!" },
