            { 738247656, "Defenselessness" },
            { 738247657, "When Frey receives damage that would reduce her health to zero, she becomes defenseless. If she takes additional damage while in this state, you immed..." },
            { 738247658, "BATTLE TUTORIAL" },
            { 738247659, "Thalia's Magic" },
            { 738247660, "The strange mark appears to have given Frey access to new magic.\n\n<buttonAttackMagic>: Cast Attack Spell\nHold <buttonAttackMagic>: Charge Attack Spell..." },
            { 738247661, "<EmptyString>" },
            { 738247700, "Hey..." },
            { 738247701, "Another one..." },
            { 738247702, "Look..." },
            { 738247703, "Another soldier..." },
            { 738247704, "I just hate seeing this..." },
            { 738247707, "Sharpness" },
            { 738247708, "Adjust the sharpness of the upscaler." },
