            { 738247710, "Evasion and Magic Parkour" },
            { 738247711, "You can use magic parkour to dodge enemy attacks in battle.\n\n\nPress <buttonParkour> at the right moment to take a quick step out of the way. You can a..." },
            { 738247712, "Battle Tutorial 5/6" },
            { 738247713, "Locking On to Enemies" },
            { 738247714, "Press <buttonLockOn> while an enemy is in view, and you'll see that the lock-on icon appears, and the enemy in question remains fixed in the center of..." },
            { 738247715, "<buttonLockOn>: Lock On" },
            { 738247716, "Battle Tutorial 6/6" },
            { 738247717, "Dodge Rolls" },
            { 738247718, "If you use magic parkour while preparing a spell, you can make an even bigger evasive maneuver than the usual quick sidestep.\n\n\nPrepare an attack or s..." },
            { 738247719, "We thank you for all you have done. May you rest in peace..." },
            { 738247720, "Your death will not be in vain. I promise." },
            { 738247721, "I'm sorry I was not here to protect you." },
            { 738247722, "You were brave until the very end, my friend." },
            { 738247723, "I will make everything right. You have done Athia proud." },
            { 738247724, "I'm good." },
